INSERT INTO `Book` (`title`, `author`, `price`, `imageUrl`, `description`, `inStock`, `featured`, `createdAt`, `updatedAt`) VALUES
  ('Genijalci bez gaća', 'Slavko Pregl', 10.00, '/images/knjige/1.webp', 'Genijalci su srednjoškolci kojima je svejedno i žele drugačiji svijet. To žele promijeniti internetskim novinama, u kojima hrabro otkrivaju svijet u kojem žive: nasilje među mladima, eksperimente s drogama, ljubavne afere, aktualnu svjetsku politiku... Zbog svog poriva često upadaju u nevolje. Između glavnih likova stvaraju se savezi i stvaraju se trvenja; upoznaju svoju prvu ljubav i sex... Pregl je, dakle, odradio težak zadatak... izvrsno i dokazao da (ipak) dobro poznaje zamke umova mladih, a ni ovoga puta nije zanemario njihovu “genijalnost”. Ako išta, povećao se. A koji tinejdžer ne bi rado pročitao djelo prožeto pozitivnim pogledom na sva tinejdžerska iskustva i postupke, a dodatno prošarano prepoznatljivim smislom za humor.', 1, 0, NOW(), NOW()),
  ('Balkanski mafiozo', 'Pavle Pavlović', 10.00, '/images/knjige/2.webp', 'Još koji minut i evo nje, mlade, lijepe komšinice. Ponosno, kao predsjednica iz susjedstva, što je nedavno pohodila Stambol, stupa za zategnutim dugačkim kožnim kaišem na čijem kraju veselo skakuće njen kućni ljubimac. A, evo i mene da se još jednom, kao fol, oduševljavam slatkim Bobom. Ljubazno se pozdravljamo i ja odmah kako je Bobica? Je li pajkio, je li papio? Poput brižne mamica radosno odgovara da je sve OK i da je kao i svakog dana, vrag mali, jedva dočekao da, uvijek u istu uru, prošeta šarenu njuškicu po hladnom zimskom zraku....', 1, 0, NOW(), NOW()),
  ('Kap tinte', 'Enver Enko Mehmedbašić', 15.00, '/images/knjige/3.webp', 'Enko Mehmedbašić je ne samo najbolji već i daleko namoderniji bosansko hercegovački humoristički satirični pisac.Nadasve jedna visoko književno artikulisana i tipično sarajevska kombinacija vedrine, melanholije, privrženosti malom čovjeku i one zoščenovske čežnje za lijepim. U njegovom humorističnom i satiričnom pogledu na svijet ima i prave mudrosti, mudrosti da se duhom i humorom premoste, prevaziđu i savladaju silne neprijatnosti, gluposti i ograničenosti svijeta kojim putujemo, vremena u kome živimo.Ovo je izbor koji će ponovo oduševiti čitalačku publiku, kako dobrodušnim humorom, tako i sjajnim stilom jednog neponovljivog romantika koji je dokazao ne samo da je humor lijek za dušu, već i da su putopisi najkreativniji dio novinarstva, koji spaja žurnalizam i književnost.', 1, 0, NOW(), NOW()),
  ('Agonije', 'Alen Kristić', 10.00, '/images/knjige/4.webp', 'gospode kad si izborom muškog mesije u svom misaonom svijetu abortirao ženskog jesi li znao da će crkva na toj stabljici nakalemit prijetvoran kalem isključenja žena s kastrirajućim vrškom u tvom crkvenom portretu', 1, 0, NOW(), NOW()),
  ('Licem u Face B', 'Zoran Kurtović', 10.00, '/images/knjige/5.webp', 'Kratke priče Zorana Kurtovića, priče su o ljudima, snovima, strahovima, putovanjima... Njegove priče vole da odjenu lice o kome priča u odore koje priča želi da ono nosi, pa čak i da razmjesti njegove dane onako kako on misli da je to najbolje… A i sam zaplet priča zna da osmisli, i da ličnosti postavi na najbolja mjesta, i da im najneusiljenije poze odabere, i potrebnim pokretima da ih snabdije, i riječima da ih nauči, onim riječima koje oni treba da kažu da radnja bude prirodna, likovi životni i da niko u priči nikada priču ne prepozna...', 1, 0, NOW(), NOW()),
  ('Podmukla tišina', 'Nikola Vuksanović', 10.00, '/images/knjige/6.webp', 'Kriminalistički roman “Podmukla tišina” bavi se istragom tajanstvenog zločina s radnjom smještenom u današnjem Sarajevu. Knjiga govori o običnim ljudima, koji su različite vjere i nacije, ali žive i funkcionišu sasvim normalno, dok se kroz njihove živote prožimaju standardni motiv žanra poput ljubavi, prevare, izdaje, ali i samog zločina koji u potpunosti mijenja živote tih ljudi. Naravno svi likovi i događaji su izmišljeni uz naglasak da je knjiga u potpunosti lišena nacionalističke pozadine, pa zbog toga donekle podsjeća na predratnu literaturu...', 1, 0, NOW(), NOW()),
  ('Slike iz albuma odrastanja', 'Željko Ivanković', 10.00, '/images/knjige/7.webp', 'Željko Ivanković je, uza sve drugo i autor proze za djecu. Jedna njegova knjiga, kako je poznato, nalazi se u lektiri za osnovne škole, ali on ne prestaje pisati i za djecu. Priče za djecu. Njegova nova knjiga, nakon knjiga priča „Zvjezdangrad“ i „Odrastanja“ nosi naslov „Slike iz albuma odrastanja“ u kojoj je 25 novih kratkih priča za djecu i o djeci. Riječ je o pričama koje pričaju svijet iz dječje perspektive, nimalo infantilne, nimalo infantilizirane, ali perspektive koja se pokazuje otvorena za dječje viđenje svijeta u kojemu žive, rastu, odrastaju, otkrivaju i spoznaju svijet, tragaju za njim u stvarnosti i u jeziku.', 1, 0, NOW(), NOW()),
  ('Šabanova kafana', 'Šerifa-Šaka Šarac', 10.00, '/images/knjige/8.webp', '„Pojavljivanje Šerife-Šeke Šarac na književnoj sceni Bosne i Hercegovine prije 13 godina, sigurna sam, u svakoj zemlji koja drži do pisane riječi, bila bi svojevrsna senzacija, a kod nas je to prošlo gotovo potpuno nezapaženo. Dok čitate Hatu mlinaricu, Kijametski dan, Uranak, Šabanovu kafanu, Pašinsko koljeno, Sudbinu, Sreća se ne kupuje, Srodne duše, Seosku učiteljicu, obuzme vas osjećaj kao da su se svi naši antropolozi, lingvisti, historičari, folkloristi, muzikolozi sastali i potom odabrali onu među njima Sarajevo je imalo i ima mnoge svoje hroničare. Osjećam, Bašeskiji, najvećem od njih, najviše se približila Šerifa-Šeka Šarac. Ko u ovo sumnja neka pročita makar jednu od njenih priča poslije čega će njegova slika staroga Sarajeva, ljudi, običaja, vrijednosti, uvjerena sam, biti puno jasnija nego danas.“', 1, 0, NOW(), NOW()),
  ('Tajna se zove Erih knjiga 1. i 2.', 'Slavko Pregl i Leon Pogelšek', 20.00, '/images/knjige/10prvi-dio.webp', 'U kratkom životu i radu Eriha Šlomovića ima mnogo toga što će zauvijek ostati tajna. Najviše maštu uznemirava činjenica da se ne poklapa broj umjetničkih djela koja je mladi galerista i ljubitelj umjetnosti sakupio sa stvarnim brojem do sada nađenih i evidentiranih djela. Da li su se izgubila na putu od Zagreba do Beograda, koliko ih je uistinu nestalo u željezničkoj nesreći… ? O tajnama i zapletima u vezi sa likovnom zbirkom Eriha Šlomovića objavljeno je bezbroj tekstova u domaćoj i stranoj štampi. Povremeno, kao što se to prije nekoliko godina desilo u Bavarskoj, na tržištu umjetničkih djela nađu se djela „iz izgubljene kolekcije“ Eriha Šlomovića. O jednom od takvih nalaza, koji su otkrili i u svijet poslali majstori svog zanata u malom selu sred panonske ravnice blizu Pančeva u Srbiji, govori ovaj roman.', 1, 0, NOW(), NOW()),
  ('Vrteška života', 'Ivan Vanja Borisoglebski', 10.00, '/images/knjige/12.webp', 'Zbirka pripovjedaka autora Ivana Vanje Borisoglebskog.', 1, 0, NOW(), NOW()),
  ('Zapisi sa plaže jednog Sarajlije', 'Branko Popović', 10.00, '/images/knjige/13.webp', 'Autor kaže: „Ovih tridesetak kratkih priča su nastale u periodu od dvadesetak godina. Pisane su bez ambicija da ikada budu objavljene. Naravno, nisu pisane 20 godina, nego upravo onoliko koliko je potrebno da se iste i pročitaju. Pisane su u autobusu, avionu, na brodu, u kafani, na koljenima, za šankom, u ležaljci na plaži, pored štafelaja i nijedna onako kako smo gledali u starim filmovima - za velikim pisaćim stolom zatrpanim knjigama i obaveznom korpom za otpatke u kojoj je gomila zgužvanog papira nezadovoljnog autora. Pisane su ,,kad mi dođe“.', 1, 0, NOW(), NOW()),
  ('Zvijezde nekog drugog neba', 'Ildiza Hadžajlić Kuburović', 15.00, '/images/knjige/14.webp', 'Autorica svoju prvu knjigu, a bit će ih sigurno još, ispisat će sitnim, naoko beznačajnim ali dragocjenim sjećanjima. Piše o svakodnevnim događanjima, prirodi (Sjeničani su vezani za prirodu kao listovi jednog drveta), godišnjim dobima, kućama i nadasve ljudima njenog rodnog kraja. Njena Sjenica je imala oči, ali i dušu, Ildiza je bez ostatka voli, pričajući autentične i čedne zapise o čistoti jednog grada i jednog vremena, proživljeno i uvjerljivo, da i oni koji ne poznaju taj kraj, osjete čudnu toplinu hladne Sjenice, zaboravljene ljudskosti i radosti življenja... I onda rez! Otvara se azilantska kapija...', 1, 0, NOW(), NOW()),
  ('Nedovršen', 'Branko Vlačić', 10.00, NULL, 'Knjigica - najbolja prijateljica. Praktična zbog formata, savremenog dizajna, lijepih korica i poznatog mirisa knjige, te popularnih cijena. Mala knjiga će objavljivati odabrana djela domaćih i stranih autora trilere, romane, putopise, SF romane i još puno toga. Nadam se da ćete biti zadovoljni našim izborom naslova i autora Zato potražite i vi Malu knjigu već danas. Za stare navike i nova uživanja.', 1, 0, NOW(), NOW()),
  ('Recite Selmi...', 'Vlado Dijak', 10.00, '/images/knjige/16.webp', 'Vlado Dijak autor je mnogih poznatih pjesama Selma (Bijelo dugme) ili Stanica Podlugovi (Zdravko Čolić) ili Čisti bijeli snijeg (Arsen Dedić) ili Betonska brana (Indeksi)', 1, 0, NOW(), NOW()),
  ('Amerika za početnike', 'Boro Radosavljević', 15.00, '/images/knjige/17.webp', '...Nisam vam pričao o Nikoli Tesli i Melaniji Tramp, jer o njima sve znate, a oni su samo vrh ogromnog brijega koji čine naši ljudi na ovu stranu okeana, brijega koji raste i tone u isto vrijeme. Raste tako što mi i dalje - i kad nema ratova - imamo razloga da bježimo na ovu stranu, a tone tako što sa svakom novom generacijom rođenom ovdje, sa svakim novim brakom i miješanjem, sve je više pravih Amerikanaca među nama, a sjećanja na porijeklo blijedi i nestaje. Vrijeme sve ravna, poravnava i poravnava, i svodi nas na livade svakog proljeća prekrivene novom travom, ispod koje su brižno složene kosti i predaka koji su prošli kroz Blajburg, i onih što su preživjeli Jasenovac ili Srebrenicu, i pobjednika i gubitnika u našim ratovima, žestokih kao i nas kojima je nacionalnost samo genetska oznaka a međusobna ubijanja naše zajedničke tragedije, milionera i prosječnih Amerikanaca koji su rođeni s tu stranu velikog mora. Sve se tu, šest stopa ispod zemlje, poravna i svede na jednu priču, vječni mir i tišinu, bez izuzetka...', 1, 0, NOW(), NOW()),
  ('I pad je let', 'Miloš Čorak', 10.00, '/images/knjige/19.webp', '“I pad je let“ je roman zasnovan na pesmi Duška Trifunovića. Poglavlja u knjizi su podeljena po stihovima pesme i kazuju nam s jedne strane šta se krije iza istih. Priča je bazirana na dokumentarnom i imaginarnom postupku. Autentične lokacije, datumi, diskografski podaci za cilj imaju da ubede čitaoca u uverljivost same priče (dakle, da se postigne iluzija istinosti) ali isto tako i da sačuvaju od zaborava jedno vreme. Imaginarni postupak kroz koji se priča razvija uvodi čitaoca u jedno putovanje sa ishodom koji je isključivo ostavljen čitaoca da odabere kakav će biti. ... Predstavljanjem diskografije Indexa (jednog njenog dela) čitaocu se sugeriše na nepostojanje bilo čega sličnog u sadašnjosti. Takođe ukazuje na činjenicu da je njihova sveprisutnost(Indexa) nije samo odraz kvaliteta i čiste umetnosti već i ukazivanje na nepostojanje slične danas...', 1, 0, NOW(), NOW()),
  ('Ko je ubio predsednika', 'Duško Anđić', 10.00, '/images/knjige/20.webp', 'Još jedan roman Duška Anđića pisan osobitim stilom dramskog pisca sa sezibilitetom filmskog reditelja. Dakle, krcat likovima, nizanjem slika tijekom svijesti i razvojem radnje imanentne krimi priči. To je forma kojom, uvjerili smo se i ranije, Anđić suvereno vlada. Kojom drži pažnju i vješto nas vodi kroz koloplet dramskih tokova i sudbina jasno podijeljenih u skupine međusobno suprotstavljenih ljudi u permanentnom i razložnom sukobu.Tu su: naravno Vlast, sa svim svojim satrapima koji joj vise o bokovima i po pravilu pripadaju, te nevinih žrtava bez kojih bi moć Vlasti bila obesmišljena, pa samim tim bi i ova knjiga ostala nenapisana. Ovako evo,čitamo je i ona plijeni!', 1, 0, NOW(), NOW()),
  ('Kako će Sarajevo bez sarajlica', 'Izet Kiko Sarajlić', 10.00, '/images/knjige/21.webp', '…Pa, nekako će se već snaći… Ali, mi ćemo se još sastajati. Ja sam bio - pjesnik. Kad god mom gradu bude potrebna nježna riječ, ja ću tu biti…', 1, 0, NOW(), NOW()),
  ('Ljubav u kolibi', 'Ilija Ladin', 10.00, '/images/knjige/22.webp', 'Izdavačka kuća Art Rabic je u svojoj maloj biblioteci već prezentirala jedan broj najznačajnijih djela i autora naše književnosti, među kojima i značajan broj pjesnika. Objavljivanje izabranih pjesama „Ljubav u kolibi“ jednog od najznačajniji bosanskohercegovačkih pjesnika prošloga stoljeća, Ilije Ladina (1929.-2001.), dolazi dvadeset godina nakon njegove smrti i najbolji je način da se taj pjesnik još jednom prezentira javnosti. Knjiga čini izbor od 80 pjesama iz Ladinovih osam autorskih knjiga. Izbor je napravio Željko Ivanković, autor koji je uradio izabranu poeziju Ilije Ladina sad već davne 1999. godine u dosad najreprezentativnijem izboru, a kao jedan od najboljih poznavatelja njegove poezije.', 1, 0, NOW(), NOW()),
  ('Teška industrija', 'Duško Trifunović', 10.00, '/images/knjige/23.webp', 'Znam zašto Hoću da budem čovekolik i kad mi izvrate kožu znam zašto možda baš znam i šta sam ali ćutim. Širok sam nekako i dozvoljavam da se rašire ruke ali ne dirajte mesečaru u mesečeve moći...', 1, 0, NOW(), NOW()),
  ('Što te nema i druge tuge', 'Aleksa Šantić', 10.00, '/images/knjige/24.webp', 'Niti jednom od južnoslavenskih pjesnika kao Aleksi Šantiću ne pristaje usvjetna Miroslava Krleže: Vrijedi samo onaj spomenik koji je rušen tri puta. Ne postoji grad na južnoslavenskim prostorima koji se tako ljupko, vjerno i rodbinski prisno poistovjetio i ponosio svojim pjesnikom, niti pjesnik svojim gradom kao što su Mostar i Aleksa Šantić. Ne postoji grad koji je igdje toliko ličio na sebe kao Mostar u njegovim pjesmama, niti pjesnik koji je cjelokupnim djelom toliko ličio na rodni grad koliko Aleksa na Mostar. Preživjeli su hropac dva carstva i krvav porod jedne monarhije podjednako uspravni i gordi, u uzajamnoj ljubavi i poštovanju. Mostar i njegov pjesnik su bili jednojajčani blizanci. Autor “Emine”, po muzikolozima najpjevanije pjesme u istoriji Balkana, sem u jedinoj uzvraćenoj sa gradom - savremenikom, nije imao sreće u ljubavima. Šantić je duhovno najljepši i sudbinski najtužniji Mostarac.', 1, 0, NOW(), NOW()),
  ('Brzim preko Bosne', 'Arsen Dedić', 10.00, '/images/knjige/25.webp', 'Dugo mi je trebalo da shvatim kako postoje knjige koje nikako ne treba držati, u kući, među svim ostalim knjigama, u dnevnorn boravku, nadohvat oku i ruci jednako domaćinu i gostu.', 1, 0, NOW(), NOW()),
  ('Povratak Mostaru', 'Pero Zubac', 15.00, '/images/knjige/26.webp', 'Četrdeset godina skoro, posle Mostarskih kiša, tog jedinstvenog krika mladosti, kako nedavno reče Milan Komnenić, počele su da se nižu pesme ciklusa Povratak Mostaru tkane od slika iz sjećanja, duboko lične i bolne a opet meke kao marama iz sjećanja kojom mi je majka sklanjala bolju sa čela.', 1, 0, NOW(), NOW()),
  ('Glasovi u tišini', 'Pero Zubac', 15.00, '/images/knjige/27.webp', 'Ovu knjigu Pere Zupca osobno smatram trujumfom njegovog pjesničkoga djela, i ozbiljnim datumom u kulturi sva tri njegova osobna, državna i pjesnička identiteta. Knjiga je ovo izbrušenog, i to do kraja (!) pjesničkog, dubinski zasnovanog vjeruju, svojevrsna nadgradnica ukupnog Zupčevoga pjeva, koja se čita od korice do korice, bez daha, ali sa jasnom predodžbom da pjesnikova lirska subjekcija uporišne međaše nalazi u duboko proživljenim pjesnikovim fascinacijama malim, običnom stvarima, pojavama, oljuđivana i poetski isklesavana od Nevesinja, preko Mostara, Novog Sada i Beograda, do svih svjetskih duhovnih postaja i privremenih staništa pjesnika Pere Zupca. Gradimir Gojer', 1, 0, NOW(), NOW()),
  ('Zapisi iz tihog vremena', 'Pero Zubac', 15.00, '/images/knjige/28.webp', 'Zapisi koji slede u ovoj knjizi objavljivani su kao autorske kolumne u nedeljnicima u Sarajevu, Beogradu, Zagrebu, Podgorici, Splitu, Subotici i Novom Sadu. U ovom izboru pretežno su tekstovi iz sarajevske „Nedjelje”, novosadskog „Dnevnika”, splitske „Slobodne Dalmacije”, podgoričke „Pobjede” i „Subotičkih novina”. U drugoj knjizi naći će se zapisi iz godina ratnih, poneki bitan intervju i dnevnik pisan u tim nedanima, objavljivan u „Borbi” i „Našoj Borbi”. Ništa u tekstovima nije menjano, ostavljena je i ekavica i ijekavica, zavisno od grada gde su novine izlazile.', 1, 0, NOW(), NOW()),
  ('Mostarske kiše i neka druga zemlja', 'Pero Zubac', 10.00, '/images/knjige/29.webp', 'Nova zbirka Pere Zubca,više od pola stoljeća nakon što je ukoričio prvu, „Nevermore”, s neizbježnom primisli kako bi i u ovoj prigodi odsustvo bar škrtog pominjanja literarnog legata kojim je obogatio južnoslavensku i sveukupnu književnu umjetnost bilo neoprostiv grijeh prema autoru, djelu i vjernicima u njih. Umilnijeg i ljupkijeg vodiča u davno i bolno izgubljeni raj mostarskih zvizdana koji osvježavaju, nevesinjskih snjegova koji griju, novosadskih košava koje miluju, najljubavnijih ljubavi koje ne gasnu, sem u pjesmama najstarijeg djeteta u zavičajnoj lirici nisam našao. Od vremena „Kiša” niže ih u isti lirski đerdan, samo njemu nalik sonetni vijenac ljubavi s akrostihom – posvetom svima i svemu što smo voljeli i nikad nismo prestali. Pero Zubac je najvjerniji i najljupkiji lirski hroničar svog, saputničkog i sapatničkog vremena. Po kojem će budući zaljubljeni uzdrhtala i čista srca preko vijekova nepogrješivo suditi kraj dvadesetog, početak dvadeset prvog milenija i najčasniji dio njihovih podstanara.', 1, 0, NOW(), NOW()),
  ('Odlazak', 'Tin Ujević', 10.00, '/images/knjige/30.webp', 'Čim se objavila u svojoj veličini, Ujevićeva poezija predstavila se kao izazov: i čitateljstvu i našoj književnoj, pjesničkoj tradiciji. I to dvostruki izazov, s dva suprotna predznaka. Jednu od njih prihvaća, ali ne zato da joj se pokori nego da se nadmeće s njom. Drugu otklanja i pobija. Hrvatska renesansna i barokna pjesnička riječ bila je glas europskoga kulturnog podneblja. S tim podnebljem Ujevića vežu i odgoj i naobrazba. To je dakle tradicija kojoj se obraća i kojoj želi pripadati. Zato u njegovu pjesništvu ima i renesansne razigranosti i neobarokne kićenosti. S preporodom u XIX. stoljeću počinje naše nesretno zaostajanje. Hrvatski pjesnici kao as u u tom trenutku posumnjali u svoje pravo na estetsku autonomiju; svjesni težine povijesnog trenutka u kome se tada nalazio hrvatski narod, oni su preuzeli na se krupne nacionalne zadatke, podredivši im i svoje umjetničke želje. Nastaje oblik hibridne književnosti, koja u službi nacionalnih ciljeva zadovoljava političke i društvene potrebe, ali zanemaruje umjetnost. To pjesničko nasljeđe Ujević ne prihvaća i pobija. “Sto glasova iz stotine grla, iz dubina stostruke mi svijesti […]”.', 1, 0, NOW(), NOW()),
  ('Orfej iz doline željeza', 'Željko Ivanković', 10.00, '/images/knjige/1020.webp', 'Riječ o izboru od 130 pjesama, koje je predgovorom popratio priređivač, izboru pridodajući i Ivankovićev lirski Putopis iz Doline željeza, te fragmente autorovih refleksija o vlastitoj poetici izabrane iz njegovih autopoetičkih intervjua.', 1, 0, NOW(), NOW()),
  ('Neum Casablanca', 'Dragan Markovina', 15.00, '/images/knjige/32.webp', 'Trokut Markovinine putanje čine spojevi triju njegovih adresa: korčulanske, splitske i mostarske, a u njegovom se središtu, simbolički više negoli matematički, nalazi Neum, o koji se autor spotaknuo i zastao, spreman da nas upozna s boljim, prošlim vremenom ovog grada, koji on ne vidi kao konačnu nepovratnost koju treba pamtiti, nego i kao ideju koju treba ugraditi u sva naša promišljanja budućnosti, ako s budućnošću uopće računamo. Autor u svojim zapisima kombinira svoj povjesničarski nerv, svoje znanje, ali i posve subjektivni rakurs iz kojeg gleda jedan kompleksan prostor iščitavajući ga kao palimpsest i otkrivajući sve njegove slojeve.', 1, 0, NOW(), NOW()),
  ('Dugo, bolno putovanje za San Francisko', 'Boro Radosavljević', 10.00, '/images/knjige/33.webp', 'U sudbinskom, psiho-dinamskom smislu, nije teško vidjeti da u njemu sve vrvi od nemira i mijena bolnih životnih obrata: saobračajnih nesreća, nikad dokućenih ljubavnih ubistava i samoubistava; raznih bolesti, sljepila i gluhoća, koji stvarnim likovima porodičnog kruga, tegobom boje njihove tragične živote.', 1, 0, NOW(), NOW()),
  ('Pun mjesec u škorpiji', 'Zora Vujasin Di Gallo', 10.00, '/images/knjige/34.webp', 'Iza naslova sa snažnim poetskim nabojem, s nevjerovatnom iskrenošću i lakoćom, autorica izlijeva pred čitaoca svoju dušu, bez zadrški i kompleksa, bez gorčine i bez iskliznuća u patetiku ili samosažaljenje. Svoju životnu priču, punu smijeha i suza, autorica prezentira sa istančane ironijske distance, sa izuzetnim osjećanjem za mjeru i bez ijedne suvišne emocije.', 1, 0, NOW(), NOW()),
  ('Razbijeni kaleidoskop', 'Jasna Šamić', 15.00, '/images/knjige/35.webp', 'To je knjiga, na šta i naslov sugeriše, roman o “razbijenoj porodici” i “razbijenom životu” glavnog junaka Adnana. On će to i sam potvrditi na početku knjige, ispovijedajući se naratorki, pominjući joj igračku koju mu je otac razbio. To je početak njegove drame. Roman se čita u dahu, držeći čitaoca od prve do posljednje strane, jer nam naratorka vrlo uspješno dočarava cijeli Adnanov život, od njegovog djetinjstva u Sarajevu, sve do časa kad mu se čini da mu se bliži kraj u Australiji, gdje živi odavno kao izbjeglica. Mnogi će možda prepoznati priču o poznatoj sarajevskoj porodici, iako autor kaže da je riječ o fikciji i da računa na inteligentnog čitaoca koji zna šta to znači. To je, rekla bih, prvenstveno roman o ljudskoj sudbini općenito, a potom o sudbini pojedinca koji je cijeli život predan porodici i poslu, ne razmišljajući ni o sebi, ni o životu. Iako junak oduvijek voli posmatrati ljude, reklo bi se da je ostao slijep na ono u što je gledao. Pitanje koje se javlja je: koliko knjige utiču na naš život? Ne vode li više u snove nego u budnost, zvanu realnost?', 1, 0, NOW(), NOW()),
  ('Kad muzika priča', 'Brano Likić', 10.00, '/images/knjige/36.webp', 'Kad muzika priča je zbirka intervjua sa muzičkim stvaraocima. Knjiga je nastala iz ljubavi prema muzici i poštovanju prema njenim stvaraocima.', 1, 0, NOW(), NOW()),
  ('Pjesmo moja', 'Antologija pjevane poezije sa CD-om', 40.00, '/images/knjige/37.webp', 'Autor Mišo Marić je napisao više od 200 hitova za pjevače i bendove u bivšoj Jugoslaviji, poput Zdravke Ćolića, grupe Cod, Ambasadori i drugih.', 1, 0, NOW(), NOW()),
  ('Karabaja', 'Nadan Filipović', 15.00, '/images/knjige/38.webp', 'Sjećanje na legendarnog sarajevskog psihijatra i primjeri omenoloških „slučajnosti“ iz njegove prakse... Doktor Salvator Karabaić, kojeg su većina Sarajlija i mnoštvo njegovih pacijenata “prekrstili“ u doktora Karabajića, bio je “bolesnička majka”. Doktor Karabaić je bio stvarni posvećenik svoga posla, koji je svoju bolnicu doživljavao onako kako bi neki starodrevni redovnik, gvardijan kakvoga bosanskog franjevačkog samostana u turska vremena, doživio, gradio i štitio svoj manastir. Bolnica je bila njegova država u državi. A psihijatrijska je bolnica u toj državi u državi još jedna zasebna država.', 1, 0, NOW(), NOW()),
  ('Studio BLAP - muzika za sva vremena', 'Pavle Pavlović', 15.00, '/images/knjige/39.webp', 'Priča o sarajevskom muzičkom studiju BLAP gdje je snimljeno preko 500 muzičkih programa svih mogućih žanrova koji su obilježili muziku jednog vremena. Njegov idejni tvorac Brano Likić, jedan od stubova istorijske sarajevske pop-rock škole, veliki zaljubljenik u muziku i entuzijasta pomogao je da se ostvare mnogi snovi i dao šansu svima koji su htjeli da se pokažu u muzici. Tu su snimali poznati i nepoznati, mladi i iskusni, muzičari iz cijele BIH, iz velikih gradova i malih mjesta. Knjiga je svjedočenje desetine umjetnika koji su učestvovali u stvaranju muzike u BLAP-u. U njoj se spominje preko 400 imena koja su pisala istoriju bosansko hrcegovačke muzičke estradne i umjetničke scene. Ovo je priča koja govori kako se stvarala muzika, priča koja otkriva tajne, ovo je priča o neumornoj i beskrajnoj snagi nota. Pavle Pavlović nam iz „prve ruke“ daje nevjerovatne podatke i priče kako su svi oni a neki i završavali...', 1, 0, NOW(), NOW()),
  ('Dnevnik jednog apatrida', 'Milenko Mišo Marić', 15.00, '/images/knjige/40.webp', 'Ovu knjigu napisao je Mišo Marić, Čovjek s Dušom, i još uz to - Čovjek, pjesnik, s Dušom Mostarca. Mostar je (bio) Grad s Dušom, a u njoj Mišo Marić, Čovjek s Dušom. Ispunjen Dušama onih koje je volio i koji su njega voljeli. Ljepotau Dobroti, i Dobrota u Ljepoti. Sve drugo je prolazno. O tome priča ova knjiga.', 1, 0, NOW(), NOW()),
  ('Jest ćemo zlatnim kašikama', 'Margit Tomik Levy', 15.00, '/images/knjige/41.webp', 'Verovati političarima i njihovim obećanjima je đavolji posao. Sve što obećaju, lažu, sve što mogu, ukradu... A, mi smo im poverili državu i naše pare. Koji smo mi kreteni. Milion puta bi naše pare bile sigurnije kod rahmetli Hajre Hastora nego kod Čovića, Bevande, ludog Milojka, Šarovića, Bakira ili Fadila. Milion puta... Setite se prvih obećanja pre tri decenije. Jedan nesposobni pravnik, koji nije dalje dobacio od kadrovika u građevinskom preduzeću se dokopao države i obećao da ćemo kusati zlatnim kašikama iz zlatnih sahana. Evo nas, tu smo. Ne jedemo zlatnim kašikama nego “jedemo” zlatne kašike. Koje su naše bake donele u miraz. Bar oni koji su imali “ispravne” bake. Kakve zlatne kašike, kakve trice i kučine...Tu smo negde blizu vojničkih limenih porcija. A i iz njih se ima sve manje kusati...', 1, 0, NOW(), NOW()),
  ('"Ja, i?"', 'Margit Tomik Levy', 15.00, '/images/knjige/42.webp', 'Zbirka facebook-postova Margit Tomik Levy „Ja, i?“ objavljene u „Maloj biblioteci“ izdavačke kuće Art Rabic su i te kako potrebne u BiH i za aktuelni trenutak i za budućnost – oni su glas javnosti, većine onih koji ne pripadaju vladajućoj kasti vladajućih političkih partija, onih koji nisu sretni u aktuelnom trenutku ili ne nalaze zadovoljstvo u njemu. Tomik Levy u svojim komentarima ne štedi nikoga, ni donosioce odluka ni narod, a uz to je duhovita, pametna,žilava, brižna, uplašena, ljuta... i piše ono što drugi misle, ali ne smiju – zbog posla, zbog djece, zbog šefa, zbog komšija, zbog rođaka... i zato je važno da njene bičješke ili postovi ostanu sačuvani i na ovaj način jer zapravo istorija pokazuje da medijski izvještaji ili udžbenici istorije ne moraju uvijek donositi istinu, onu istinu koju stanovnici određenog prostora u datom trenutku ili većina njih misle i osjećaju.', 1, 0, NOW(), NOW()),
  ('Bašta ukrašena flamingosima', 'Antonije Nino Žalica', 15.00, '/images/knjige/43.webp', 'Prolazak kroz baštu ukrašenu flamingosima pruža nam mogućnost da iz nje izađemo oplemenjeniji no što smo to bili.', 1, 0, NOW(), NOW()),
  ('Priče', 'Isak Samokovlija', 10.00, '/images/knjige/46.webp', 'Književno djelo Isaka Samokovlije ostaje da živi i kroz nove izdavačke pothvate kakav je i ovaj Art Rabica i Gorana Mikulića. Na njegovo književno djelo mnogo je utjecalo odrastanje uz rijeku Drinu u Goraždu. U njegovim djelima, dominantan je motiv tragedije njegovog naroda, ali i motivi prolaznosti, ništavila i postojanja. Ivo Andrić ga je nazvao jednim od najboljih pisaca koje je Bosna i Hercegovina dala, a Meša Selimović je rekao kako je Samokovlija, izuzmemo li Andrića, najbolji bosanski pripovijedač poslije Kočića. Sa užitkom ćete čitati njegove priče: - Nosač Samuel - Rafina avlija - Saručin drug – Simha - Solomonovo slovo - Kako je Rafael postajao čovjek - Jevrejin koji se subotom ne moli Bogu – Kadiš - Mirjamina kosa.', 1, 0, NOW(), NOW()),
  ('Diplomatski koktel', 'Slobodan Stajić Elefterios', 15.00, '/images/knjige/47.webp', 'Kad je Grčka Turska, a Slovenija Slovačka', 1, 0, NOW(), NOW()),
  ('Dogovor u Karađorđevu o podeli Bosne i Hercegovine', 'Miloš Minić', 15.00, '/images/knjige/48.webp', 'PRED ČITAOCIMA je, u tekstovima što slijede, predstavljen jedan broj novih radova sabranih u djelu iz pera Srbina, autora iz Beograda, kao glavnog grada zemlje koja je 1992. godine oružjem nasrnula na suverenu i nezavisnu državu nastalu na prostorima bivše SFRJ. Autor ovog djela je Miloš Minić. On je na uvodno mjesto u knjizi uvrstio svoj najobimniji istraživački prilog, posvećen pregovorima između Miloševića i Tuđmana o podjeli Bosne i Hercegovine u Karađorđevu, marta 1991. između Srbije i Hrvatske. U podlozi ovog rada su njegova trogodišnja istraživanja, kojima je, ustrajno i sistematično, istakao raznobojni mozaik do danas dostupnih saznanja o tome kako je prilikom tih susreta dvojice državnika iz Srbije i Hrvatske u tajnosti dogovoreno prekrajanje tada još postojeće savezne države. Glavni akteri takvih dogovaranja urotnički su skrivali svoje namjere od ostalih republika i državnih institucija jugoslovenske federacije...', 1, 0, NOW(), NOW()),
  ('Kroz karavakat', 'Nadan Filipović', 10.00, '/images/knjige/49.webp', 'Nakon događanja 1992.-1995. u Bosni i Hercegovini, rat je ponovno gotovo nezaobilazan motiv; potreba pisanja i iznošenja na svjetlo dana jedan od hiljadu načina na koje je taj rat mučio, ponižavao, doživotno traumatizirao i uništio brojne obitelji, generacije nedužnih ljudi. Sadržaj knjige Nadana Filipovića „Kroz karavakat“ nije smješten u nevrijeme bliskih nam događanja u našoj zemlji, već u vrijeme Drugog svjetskog rata. A mogao je. Jer, karavakt je nevakat svakog rata. No, Filipović u uvodnim napomenama podcrtava da je njegov glavni junak, Rušid, stvarna ličnost, te da će se u svojoj „priči“ oslanjanjti na stvarnost i stvarnosnu građu. Zato rukopis sadrži „sirove“ dokumente – spiskove ubijenih, tekstove proglasa, stihove himni i veličanja „svojih“, što ima nespornu motivacionu i dokumentarnu funkciju.', 1, 0, NOW(), NOW()),
  ('Čekajući Dylan Doga u Srebrenici', 'Dragan Bursać', 15.00, '/images/knjige/50.webp', '“ Postoje samo dvije vrste ljudi: s jedne strane pravednici koji se smatraju grješnicima, a s druge grješnici koji se smatraju pravednicima”, kaže Blez Paskal. Dragan Bursać je od ove prve vrste. O stradanju i zločinima pišu mnogi, ali je Dragan jedinstven u poziciji onih koji ne pristaju na relativizaciju motiva i cilja u ratovima devedesetih, pa secira svaki segment politike koji je doveo do genocida, masovnih zločina i etničkih progona, prepoznajući ih u mitomansko ratnim narativima savremene politike. “Čekajući Dylan Doga u Srebrenici” je beskrajno tužna i uznemirujuća, ali istovremeno i knjiga - riznica nade. Uvijek i svuda takve su knjige dragocjene. U društvima okovanim etnofilijom, društvima koja funkcionišu kao zajednice hipokrizije i laži, Bursaćeva knjiga je još važnija. Njena vrijednost i snaga ne mogu biti precijenjene. Jer ona nas uči: ne zajednica krvi, nego zajednica vrijednosti. Ne etnička, nego etička zajednica.', 1, 0, NOW(), NOW()),
  ('Derviš i smrt', 'Boris Dežulović', 15.00, '/images/knjige/51.webp', 'Dežulović je tokom 35 godina bavljenja novinarstvom uvek imao svoj stav: jasan, dorečen, argumentovan i angažovan. Dežulović svojim tekstovima nikoga ne ostavlja ravnodušnim i bespoštedno kritički analizira tegobnu hrvatsku, ali i širu regionalnu zbilju. Bez ikakve je dvojbe, korifej slobodnog i objektivnog novinarstva na ovim »regionalnim« prostorima i pri tomu intelektualno superiorno, ali i pošteno, bez dlake na jeziku često iznosi provokativne stavove kojima pogađa bit problema, a koje nam licemjerne političke, intelektualno-domoljubne i klerikalne elite nameću i predstavljaju kao jedinu moguću realnost i Bogom dano rješenje. Dežulović u svojim tekstovima postavlja suštinska pitanja našeg društva i vremena; naizgled humorno i satirički pojednostavljeno propituje gotovo sve probleme koji na ovaj ili onaj način utječu na naše živote i svakodnevnu egzistenciju. Stoga Dežulović s pravom nemilosrdno i riječima okrutno šiba farizeje i ikonobranitelje koji bi nam jeftino prodali ono čega nema, a o onome čega ima uporno i bezobrazno šute. Ironija, satira, blagi cinizam, sarkazam, anegdotalnost i humor, kao i lucidna duhovitost, sve su to sredstva kojima Dežulović u svom pismu sjajno barata. A ako tomu dodamo širinu spoznaja i informacija kojima raspolaže, onda imamo sliku rasnog kolumnista i polemičara, kakvih je na ovim prostorima iznimno malo.', 1, 0, NOW(), NOW()),
  ('Krik bijes', 'Boris Dežulović', 15.00, '/images/knjige/52.webp', 'Dežulović je tokom 35 godina bavljenja novinarstvom uvek imao svoj stav: jasan, dorečen, argumentovan i angažovan. Dežulović svojim tekstovima nikoga ne ostavlja ravnodušnim i bespoštedno kritički analizira tegobnu hrvatsku, ali i širu regionalnu zbilju. Bez ikakve je dvojbe, korifej slobodnog i objektivnog novinarstva na ovim »regionalnim« prostorima i pri tomu intelektualno superiorno, ali i pošteno, bez dlake na jeziku često iznosi provokativne stavove kojima pogađa bit problema, a koje nam licemjerne političke, intelektualno-domoljubne i klerikalne elite nameću i predstavljaju kao jedinu moguću realnost i Bogom dano rješenje. Dežulović u svojim tekstovima postavlja suštinska pitanja našeg društva i vremena; naizgled humorno i satirički pojednostavljeno propituje gotovo sve probleme koji na ovaj ili onaj način utječu na naše živote i svakodnevnu egzistenciju. Stoga Dežulović s pravom nemilosrdno i riječima okrutno šiba farizeje i ikonobranitelje koji bi nam jeftino prodali ono čega nema, a o onome čega ima uporno i bezobrazno šute. Ironija, satira, blagi cinizam, sarkazam, anegdotalnost i humor, kao i lucidna duhovitost, sve su to sredstva kojima Dežulović u svom pismu sjajno barata. A ako tomu dodamo širinu spoznaja i informacija kojima raspolaže, onda imamo sliku rasnog kolumnista i polemičara, kakvih je na ovim prostorima iznimno malo.', 1, 0, NOW(), NOW()),
  ('Goli i mrtvi', 'Boris Dežulović', 15.00, '/images/knjige/53.webp', 'Dežulović je tokom 35 godina bavljenja novinarstvom uvek imao svoj stav: jasan, dorečen, argumentovan i angažovan. Dežulović svojim tekstovima nikoga ne ostavlja ravnodušnim i bespoštedno kritički analizira tegobnu hrvatsku, ali i širu regionalnu zbilju. Bez ikakve je dvojbe, korifej slobodnog i objektivnog novinarstva na ovim »regionalnim« prostorima i pri tomu intelektualno superiorno, ali i pošteno, bez dlake na jeziku često iznosi provokativne stavove kojima pogađa bit problema, a koje nam licemjerne političke, intelektualno-domoljubne i klerikalne elite nameću i predstavljaju kao jedinu moguću realnost i Bogom dano rješenje. Dežulović u svojim tekstovima postavlja suštinska pitanja našeg društva i vremena; naizgled humorno i satirički pojednostavljeno propituje gotovo sve probleme koji na ovaj ili onaj način utječu na naše živote i svakodnevnu egzistenciju. Stoga Dežulović s pravom nemilosrdno i riječima okrutno šiba farizeje i ikonobranitelje koji bi nam jeftino prodali ono čega nema, a o onome čega ima uporno i bezobrazno šute. Ironija, satira, blagi cinizam, sarkazam, anegdotalnost i humor, kao i lucidna duhovitost, sve su to sredstva kojima Dežulović u svom pismu sjajno barata. A ako tomu dodamo širinu spoznaja i informacija kojima raspolaže, onda imamo sliku rasnog kolumnista i polemičara, kakvih je na ovim prostorima iznimno malo.', 1, 0, NOW(), NOW()),
  ('Razum i osjećaji', 'Boris Dežulović', 15.00, '/images/knjige/54.webp', 'Dežulović je tokom 35 godina bavljenja novinarstvom uvek imao svoj stav: jasan, dorečen, argumentovan i angažovan. Dežulović svojim tekstovima nikoga ne ostavlja ravnodušnim i bespoštedno kritički analizira tegobnu hrvatsku, ali i širu regionalnu zbilju. Bez ikakve je dvojbe, korifej slobodnog i objektivnog novinarstva na ovim »regionalnim« prostorima i pri tomu intelektualno superiorno, ali i pošteno, bez dlake na jeziku često iznosi provokativne stavove kojima pogađa bit problema, a koje nam licemjerne političke, intelektualno-domoljubne i klerikalne elite nameću i predstavljaju kao jedinu moguću realnost i Bogom dano rješenje. Dežulović u svojim tekstovima postavlja suštinska pitanja našeg društva i vremena; naizgled humorno i satirički pojednostavljeno propituje gotovo sve probleme koji na ovaj ili onaj način utječu na naše živote i svakodnevnu egzistenciju. Stoga Dežulović s pravom nemilosrdno i riječima okrutno šiba farizeje i ikonobranitelje koji bi nam jeftino prodali ono čega nema, a o onome čega ima uporno i bezobrazno šute. Ironija, satira, blagi cinizam, sarkazam, anegdotalnost i humor, kao i lucidna duhovitost, sve su to sredstva kojima Dežulović u svom pismu sjajno barata. A ako tomu dodamo širinu spoznaja i informacija kojima raspolaže, onda imamo sliku rasnog kolumnista i polemičara, kakvih je na ovim prostorima iznimno malo.', 1, 0, NOW(), NOW()),
  ('Grad', 'Branko Vlačić', 10.00, '/images/knjige/55.webp', 'Kretaivna specifičnost ove knjige ogleda se u namjernom izostavljanju imena i prezimena svih karaktera u Vlačićevim pričama osim nadimka glavne gradske lude nazvanog Aba, te malog brda Jago Mir po kojoj je ime dobila ludnica na rubu grada.Uvijek je to jedan te isti grad u različitim vremenim svoga postojanja, a odustvo bilo kakve etničke ili relegijsken oznake dovedeni su do univerzalnosti, simbolički dopuštajući doslikavanje bilo kojeg grad bilo gdje u svijetu, a za onaj u priči “Grad” autor veli da “nije ni postojao”. Ponegdje bi se mogao pretpostaviti, vjerovatno svjesno zamagljen, autobigrafski element, ali samo zbog činjenice korištenja “ja forme” od strane, također neimenovanog, skrivenog pripovjedača ovih priča.', 1, 0, NOW(), NOW()),
  ('Kraj sezone', 'Midhat Ajanović', 10.00, '/images/knjige/56.webp', 'Kraj sezone je roman distopijskog žanra čija je radnja koncentrirana na prostor današnje BiH i Hrvatske, ali i balkansko okruženje i Evropu čiji je oblik radikalno izmijenjen. Svijet nakon kataklizme u kojem živi još samo 200 milijuna ljudi, nedostatak stambenog prostora, hrane, pitke vode i energije, zatrovan zrak, te stalna opasnost on napada rojeva mutiranih insekata-ljudoždera ambijent su u kojem preostali ljudi pokušavaju organizirati novu civilizaciju. Neka vrsta trilerskog zapleta nastaje kada dvoje glavnih likova uđu u zabranjenu ljubavnu vezu...', 1, 0, NOW(), NOW()),
  ('I tebe sam sit kafano', 'Tin Ujević', 15.00, '/images/knjige/57.webp', 'Ako ne možemo promijeniti život, promijenimo kafanu', 1, 0, NOW(), NOW()),
  ('Stanari žute zgrade', 'Rizah Pašalić', 10.00, '/images/knjige/58.webp', 'Roman „Stanari žute zgrade“ je na neki način nastavak romana “Chief drvena noga” Glavni junaci su Diki, sada tridesetogodišnji glumac, i njegove supruge Ana-Mari, Dikijeva ljubav iz djetinjstva. Bosanski rat Dikija zatiče u stanu na Grbavici, sarajevskom naselju koje su 1992. zauzeli srpski vojnici, dok je Ana Mari zajedno sa njihovom kćerkom izbjegla kod svojih roditelja u Dalmaciju, a potom u Beč. Radnja se događa u ratnom Sarajevu, potom u Dalmaciji, Beogradu, Beču, a završava se u Bostonu. Roman od ratnog prerasta u ljubavni sa elemntima trilera.', 1, 0, NOW(), NOW()),
  ('Slika bez okvira', 'Branko Vlačić', 10.00, '/images/knjige/59.webp', 'Prije četrdeset godina Vlačić je objavio prvu, a deset godine poslije i drugu knjigu poezije.Dugo je u njemu “ćutala” ova treća zbirka za koju kaže da su u njoj objedinjene njegove, malobrojne “staračke pjesme. U njima se osjeća podvučena linija zrelosti poznih godina i životnog iskustva. U krajnjoj jednostavnosti njegovog poetskog vokabulara Brankove ekspresije su metaforične i simbolične i knjiga bi se mogla nazvati Vlačićevim sažetkom sažetaka.', 1, 0, NOW(), NOW()),
  ('Vođe u nedohođe', 'Ramo Kolar', 15.00, '/images/knjige/60.webp', 'Štivo u rukopisu esejističko-pripovijednog tipa i kolumnističkog „pakovanja“, autora Rame Kolara pod prepoznatljivom mašnom „Gradski dani teku“, stilizirano je analitičkosociološkom egidom, s bogatim jezikom začinjenim i humorom i sarkazmom, britkom satirom i razgaljivim domaćim humorom. Knjiga razmatra sociopolitičke teme društva i individualizaciju demokratskih tranzicionih procesa u našemu društvu. Namijenjena je svakom radoznalom čitatelju a posebno istraživačima naše sociološke zbilje, studentima, mladim novinarima i piscima, nevladinom sektoru...', 1, 0, NOW(), NOW()),
  ('Sarajevo zajedno smo rasli ja i ti', 'Goran Mikulić', 15.00, '/images/knjige/61.webp', 'Sarajevo Grad kojeg više nema. Šta nam uradiše od grada i života?! Mnogi će reći nostalgičari, jugonostalgičari smo.Da. Priznajemo, a zar može biti ružna ili „zločesta“ nostalgija. Možeš žaliti samo za nečim svojim, lijepim i dobrim... Za onim što nam je oduzeto – mogu sve ali ne mogu nam oduzeti sjećanje. 1995. dođe oslobođenje, i ko biva sad ćemo praviti i izgrađivati novu državu, ne znam šta je falilo staroj ali, eto, hajmo praviti novu. Ovaj GRAD prije nego što smo počeli da gradimo „bolju i ljepšu budućnost“ imao u bivšoj zajedničkoj državi najbolje muzičare, slikare, pisce, arhitekte, reditelje, sportiste, pjevače itd. Bili smo najbogatiji grad. Danas Sarajevo ima na grame i mrvice balet, operu, dramu, arhitekte, sportiste... u vrlo stidljivim količinama neuporedivim sa gradom koji bi trebalo da bude metropola. U Sarajevu nam fali-Sarajevo... Midhat Ajanović, Jasna Šamić, Gradimir Gojer, Zlatko Dizdarević, Predrag Finci i mnogi drugi autori nam u ovoj knjizi pričaju priče o gradu i ljudima, o Sarajevu kojeg više nema.', 1, 0, NOW(), NOW()),
  ('ZLO.ba', 'Ismar Mujezinović', 15.00, '/images/knjige/62.webp', 'Knjiga sa ovim intrigantnim naslovom zapravo je zbrika priča, priča za koje autor kaže: „ovo je sve čista izmišljotina“... Posebna vrijednost pomenutog djela je da ono na jedinstven način oslikava sarajevsku i bh. prošlost koja umnogome utiče na sadašnjost i budućnost naše zemlje. U zanimljivom, autobiografskom kazivanju, koje se graniči sa najboljom književnošću, autor uspijeva da na lagan način uvuče čitaoca u zbivanja i dane koji su bili presudni u našim prošlim, a i sadašnjim, životima vodeći nas vješto u ovo što nas sada okružuje. U naizgled jednostavnim, često duhovitim i često tužnim, storijama čitalac prodire u svijet emocija, doživljaja kojima je Ismar Mujezinović bio izložen i zaokupljen na svom višedecenijskom umjetničkom putu.', 1, 0, NOW(), NOW()),
  ('Otpjevane pjesme', 'Branko Likić', 10.00, '/images/knjige/63.webp', 'Brano Likić bh. gitarista, aranžer, pjesnik, tekstopisac, kompozitor, pjevač i producent podario nam je zbirku poezije „Otpjevane pjesme“. Zbirka ima 41 pjesmu za koje je bio autor stihova, muzike, aranžmana. U njoj oslikava kuražnost jednog bića da svojim stihom dodirne strunu našeg i podari odobrenje nesigurnosti da iskaže riječ koja tinja u utrobi. Njegovu poeziju treba čitati, ali i slušati. Živim, izražajnim stihom on stvara priču a glazbom kao plaštom ogrće Brano svoje stihove i nosi ih u sebi...', 1, 0, NOW(), NOW()),
  ('Uz Bistrik...', 'Toni Srkbinac', 15.00, '/images/knjige/64.webp', 'Knjiga Uz Bistrik je skup izabranih priča punih nostalgije za mjestom življenja na kojem je autor proveo svoje dječaštvo, momačke dane i gdje je novinario, kako to kažu oni koji žive od novinarstva. Njegove priče neće nikoga ostaviti ravnodušnim, jer svako može u njima pronaći sebe. Naročito čitaoci iste generacije.', 1, 0, NOW(), NOW()),
  ('Dan u životu', 'Zoran Kurtović', 15.00, '/images/knjige/65.webp', 'FB dnevnik u odlomcima zaludog novinara.', 1, 0, NOW(), NOW()),
  ('Sirano kao sudbina', 'Nadan Filipović', 15.00, '/images/knjige/66.webp', 'Proročanstvo ili nešto što liči na proročanstvo, ili pak neko predskazanje i ne bi bilo ono što jeste, ako ne bi bilo makar djelomično ispunjeno u makar manjoj ili većoj mjeri. Ili čak potpuno ostvareno u realnosti, upravo kao rezultat toga zbog čega je “prorečeno” i zbog čega je pretpostavljeno, te u nekim, doista rijetkim slučajevima, “uzrokuje” da se dogodi očekivani ili predviđeni događaj i na taj način i pored pretpostavljene “doze” sumnjičavosti potvrđuje vlastitu manjuviše “tačnost”. Uostalom, činjenica da nešto nikako ne može biti shvaćeno, ni objašnjeno, ne znači da nije tako, posebno kada se zna da su se neke priče iz druge ruke ostvarile kao proročanstvo, ili barem kao njegova naslućena sjena.', 1, 0, NOW(), NOW()),
  ('14. februar 1945.', 'Dragan Markovina', 20.00, '/images/knjige/67.webp', 'Mali Predrag stajao je ispred kuće i gledao kako niz prugu vode zarobljene Nijemce. Tek je ručao, a dan se već bližio sumraku, kako to u februaru već biva. Onako prepadnuti, iskidani i izgladnjeli, nisu bili ni sjena onih monstruma kakvi su mu se činili do danas.', 1, 0, NOW(), NOW()),
  ('Vlasa', 'Vlasta', 20.00, '/images/knjige/68.webp', 'Vlastimir Mijović rođen je 1956. u Foči. Završio je Fakultet političkih nauka u Sarajevu. Bio je novinar, urednik, voditelj i urednik TV emisija, politički komentator, dopisnik iz Moskve, glavni i odgovorni urednik. Napisao je više hiljada novinarskih tekstova, a imao stotine nastupa na radio i TV programima.', 1, 0, NOW(), NOW()),
  ('Labudarka i druge priče', 'Rizah Pašalićž', 20.00, '/images/knjige/69.webp', 'U vremenu koje toliko oskudijeva humorom, ljudskošću i ljubavlju, pojava ove knjige, predstavlja upravo objedinjavanje svih navedenih obilježja koja čine život smislenijim i humanijim.', 1, 0, NOW(), NOW()),
  ('The New Residents of the Yellow Building', 'Rizah Pašalićž', 20.00, '/images/knjige/70-prvi-dio.webp', 'Pašalić’s novel for adults The Residents of the Yellow Building follows the fate of the main protagonists of Chief Wooden Leg. Now in their 30s, actor Diki and his wife Ana-Mari’s lives are turned upside-down when the Bosnian war reaches their apartment in Grbavica, a suburb of Sarajevo occupied by Serb soldiers in 1992. The novel begins in wartime Sarajevo, then expands its setting to Dalmatia, Belgrade and Vienna, finally ending in Boston, in 2001. Its plot shifts from an account of war to a love story, before becoming a thriller at the very end.', 1, 0, NOW(), NOW()),
  ('Crvena jabuka - Priče za djecu', 'Rizah Pašalićž', 20.00, '/images/knjige/72.webp', 'Priče za djecu su najbolji način da djeca obilježe svoje djetinjstvo. Zato smo i pripremili ove priče koje kod djece potiču razvoj, ali i razvijaju ljubav i suosjećanje prema svim bićima. Bajke i priče potiču i produbljuju bliskost s roditeljima. Djeca pričama i bajkama proširuju svoj rječnik, dolaze do novih spoznaja, razvijaju svoje stavove te prepoznaju dubinu emocija. Sve to temelj je za odrastanje jer djeca čitanjem priča i bajki razvijaju ljubav prema knjizi.', 1, 0, NOW(), NOW()),
  ('100% Srbin, 101% Bosanac', 'Vojin Mijatović', 20.00, '/images/knjige/73.webp', 'Zapravo je moj lični doprinos u izgradnji boljeg bh. društva. Sve napisano predstavlja prkos trenutnom stanju u želji za izgradnjom bh. nacije. Ovo je i moja lična faza sazrijevanja i samosvijesnosti ko sam i šta sam ali i ko smo mi svi kao društvo. - Vojin Mijatović', 1, 0, NOW(), NOW()),
  ('Ponavljam se...', 'Margit Tomik Levi', 15.00, '/images/knjige/74.webp', 'Ovako ja mislim - ako vas ovi uhijupi lažu pljačkaju 30 godina vi opet verujete u njihove pa ponovo glasate za tu bagru, nije problem u njima nego u vama.', 1, 0, NOW(), NOW()),
  ('Sestra moja samoća', 'Pero Zubac', 15.00, '/images/knjige/75.webp', 'Pero Zubac nije tek individualna poetska nego masovna pojava u jezički našoj a po značaju evropskoj literaturi. Rijetki su autori kod nas i okolo u čijem književnom opusu se tijesni 50 poetskih zbirki, 20 knjiga pjesama za djecu, 16 antologija jugoslovenske i strane poezije, neregistrovan broj libreta od opere i filmskog scenarija o ljubavi Laze Kostića i Lenke Dunđerske do libreta za oratorije i kantate najzačajnijih praznika nezaborava u bivšoj, umorenoj državi, knjiga eseja, parodija, podjednako neznan broj TV znanih djela, predgovora, pogovora il’ osvrta na knjige poletaraca i besmrtnika pisane riječi kod nas… Od vremena „Kiša” niže ih u isti lirski đerdan, samo njemu nalik sonetni vijenac ljubavi s akrostihom – posvetom svima i svemu što smo voljeli i nikad nismo prestali. „Sestra moja samoća“ je još jedna zbirka poezije Pere Zubca, Everesta literarnog zemljopisa rodne Bosne i Hercegovine, sudbinske Vojvodine i prigrljene Jugoslavije.', 1, 0, NOW(), NOW()),
  ('Obična žena', 'Hana Konsa', 15.00, NULL, 'Zbirka pripovijetki „Obična žena“ obraća se svakoj ženi. Sastoji se od sedam priča, od kojih svaka obuhvaća jedno desetljeće u životu žene. Dvadesete, Tridesete... Osamdesete. Ovo je priča koja govori o kazni ili nagradi. „Ljubav za ljubav“ je misao koja nosi ovu priču. Ono što kroz život dajemo to na kraju života i dobivamo. Grijesi počinjeni prema drugima vraćaju nam se u situaciji kada se piramida prevrne pa oni koji su bili na vlasti postaju oni u potrebi.', 1, 0, NOW(), NOW()),
  ('...niz Bistrik', 'Toni Skrbinac', 20.00, '/images/knjige/77.webp', 'Služeći se, gotovo pa standardnom generacijskom mantrom, neke moje starije kolege, što vole da pišu i pri tome se često i rado bave uspomenama, najradije pozlate vremena svoje mladosti... Prisjete se reda, rada, socijalne sigurnosti, poštovanja komšije i drugog i drugačijeg, pričaju o ljetovanju na moru, skijanju na Jahorinama... Pritom, zaista skromno, kako su ih već naučii, istaknu i svoj doprinos tim zlatnim vremenima. Kad bih pisao pjesmu o tom fenomenu, refren bi išao nekako ovako: „O mladosti, o radosti... o ljepoto, o tugo...o, draga moja Jugo...“ Ne mogu reći ni da se moje uspomene ne uklapaju u taj nostalgični uzdah za prošlim vremenima ali, ali...', 1, 0, NOW(), NOW()),
  ('Sreća nakon sreće', 'Esad Bilal', 15.00, '/images/knjige/78.webp', '„U trenucima kada mi emocije ovladaju dušom i srcem, često mi na um padne ona o prolaznosti života. Kako volim muziku, u tom emotivnom uzbuđenju, tekstovi pjesama koje slušam, iniciraju mi sjećanja na moje životne događaje. Sjećanja se redaju jedna za drugim, a ja kao na krilima letim sa njima. Ovo moje pisanje, dragi čitaoče, želim da i tebe podsjeti na trenutke važne u tvom životu. Možda ih je bilo sličnih kao i moji. Poleti sjećanjima u susret, raduj se njima i zaboravi onu o prolaznosti života. Sretan let! Desi se sreća nakon sreće.“', 1, 0, NOW(), NOW()),
  ('Sarajevo moj grad', 'Više autora', 20.00, '/images/knjige/79.webp', 'Sarajevo moj grad naziv je knjige grupe autora objavljene u izdanju IK Rabic, čiji i sam naslov govori o čemu je riječ u njoj. U knjizi se nalaze tekstovi 19 autora koji pričaju priču o Sarajevu iz različitih kutova.', 1, 0, NOW(), NOW()),
  ('Sarajevo moj grad', 'U slikama', 15.00, '/images/knjige/80.webp', 'Priče o Sarajevu, u ovih deset knjiga, pričane su kroz priče o njegovim ulicama, trgovima, povijesnim građevinama, mostovima, histroijskim zbivanjima, kultnim mjestima, o uglednicima koji su obilježili njegovu povijest u politici, gospodarstvu, umjetnosti, kulturi, sportu, u svim djelatnostima duha.', 1, 0, NOW(), NOW()),
  ('O književnosti i piscima', 'Predrag Finci', 20.00, '/images/knjige/81.webp', 'Ovo je knjiga o književnosti i piscima. Priča o njima. Naslov knjige posudih od onih nekadašnjih, strogih pisaca udžbenika, priručnika i književnih pregleda, od onih ozbiljnih, uvažavanih profesora i marljivih teoretičara koji su sve znali, pa i što je književnost i koji su pisci dobri, a i koji nisu. Ja međutim ne pišem takvu knjigu. Ne pravim učene analize, ne iznosim mudre tvrdnje, ne poduzimam sistematska istraživanja života i djela pisaca. Ne bih to htio. Nego bih samo da redam, svoje nabrajam, pričam i u svom pripovijedanju ideja iznosim kako mislim da jest i što mislim da bi književnost mogla biti. - autor', 1, 0, NOW(), NOW()),
  ('Svjetionici', 'Antologija i monografija umjetnika Bosne i Hercegovina u dijaspori', 50.00, '/images/knjige/82.webp', 'U njoj je predstavljeno 36 bosanskohercegovačkih stvaralaca koji žive, ili su živjeli u gotovo svim dijelovima svijeta, po vlastitom izboru ili iz nužde.Neki su stvarali i prije rata, neki su posve novi, neki se povremeno vraćaju, neki su se definitivno vratili u radni kraj, nekih, nažalost, nema više među živima,ali su njihova djela ostala dio naše i dio kulture zemalja u kojima su živjeli. Neka od tih djela, bez ikakve lažne pretencioznosti, postala su i dio svjetske kulturne i umjetničke baštine. Od izuzetnog je značaja da se o tome zna i da se upoznaju nove generacije u Bosni i Hercegovini i nas u svijetu. Ova monografija je na tom tragu. Ona je dio započetog pionirskog posla građenja načina uočavanja i zapamćivanja naših bosanskohercegovačkih vrijednosti koje nastaju po svijetu i stvaranja kanala komunikacije između tih vrijednosti i njihovih stvaralaca, sa stvaraocima i vrijednostima koje nastaju u Bosni i Hercegovini. Priređivač i duhovni tvorac ove monografije Milenko Mišo Marić. On traga i nalazi da je iza svih naših velikih i malih uspjeha svuda po svijetu, u motivima slikara, u riječima pripovjedača, pjesnika i romanopisaca, u sportskim podvizima, u uspjesima mladih poslovnih ljudi, naučnika i političara znakovito prisutna Bosna.', 1, 0, NOW(), NOW()),
  ('Mostarenje', 'Mišo Marić', 20.00, '/images/knjige/1021.webp', '...Služeći se, gotovo pa standardnom generacijskom mantrom, neke moje starije kolege, što vole da pišu i pri tome se često i rado bave uspomenama, najradije pozlate vremena svoje mladosti... Prisjete se reda, rada, socijalne sigurnosti, poštovanja komšije i drugog i drugačijeg, pričaju o ljetovanju na moru, skijanju na Jahorinama... Pritom, zaista skromno, kako su ih već naučii, istaknu i svoj doprinos tim zlatnim vremenima. Kad bih pisao pjesmu o tom fenomenu, refren bi išao nekako ovako: „O mladosti, o radosti... o ljepoto, o tugo...o, draga moja Jugo...“ Ne mogu reći ni da se moje uspomene ne uklapaju u taj nostalgični uzdah za prošlim vremenima ali, ali...', 1, 0, NOW(), NOW()),
  ('1984. Olimpijada trijumfa i šansi', 'Aziz Hadžihasanović', 20.00, '/images/knjige/92.webp', 'Vrijedi, čini se, nešto izdašnje citirati sintezu sarajevskog olimpijskog duha koju je dao-tako vješto i tako nadahnuto-mladi majstor lijepe riječi, književnik i esejist Aleksandar Hemon. Ovaj naše gore list na američkom i francuskoim duhovnim prostorima, posvetio fenomenu olimpijske nostalgije Sarajeva, ali i bar dijela ove rastrzane zemlje, mudra i značajna upozorenja. Prisjetio se i lucidno, esejističkim manirom, razglobio u povodu 25 godina XVI zimskih olimpijskih igara Sarajevo 1984, ne male apsurde koji, poput hirovite bujice, plave i potapaju sve živo i mrtvo-i zemlju, i glave, i misli, i svijet, i pamčenje, i moral, i logiku...', 1, 0, NOW(), NOW()),
  ('Sarajevo 6. aprila 1992', 'Mustafa Čengić', 20.00, '/images/knjige/93.webp', 'Sarajevo 6. aprila 1992 u kojoj Mustafa Čengić iznosi svoja sjećanja na dešavanja u Sarajevu 6. aprila 1992. i ulogu tzv. Svenarodnog parlamenta. Čengić je oformio Press centar koji je 5/6, april objavio više od 80 informacija o dešavanjima u gradu u tim burnim danima (ovdje je objavljeno 67 informacija).', 1, 0, NOW(), NOW()),
  ('Bosnom hodim', 'Josip Pejaković', 20.00, '/images/knjige/94.webp', 'Kako se navodi u recenziji Esada Bajtala, kraća, strofično oblikovana kaza Bosnom Hodim Josipa Pejakovića, po autorovoj zamisli samo je uvod u knjiško koričenje njegovog cjelokupnog dramskog opusa koji priprema za štampu.', 1, 0, NOW(), NOW()),
  ('Tito za početnike', 'Više autora', 15.00, '/images/knjige/95.webp', 'Ako smrt znači vječan zalazak čovjekov među zvijezdama, onda je to riječ koju ne bih rekao. Riječ smrt, u slučaju Josipa Broza nema nikakvih šansi. Slabašno je umiranje da bi ga od ljudi odvojilo, zauvijek. Zato neću o smrti, meni se o životu govori. Meni se o Užičkoj govori kao konačištu putnika koji je poslije dugih dana, i dugih noći, sretno umoran a više mudar i vedar, prilegao među cvijeće da u miru predahne. Nahodao se, Tito, životom, uspravno. Ova knjiga, koja je namjenjena za mlađu generaciju i generacije koje dolaze, treba da dođe u što više ruku, i da se budući čitaoci osjete ponosnima što je takav čovjek bio na čelu naše kolone.', 1, 0, NOW(), NOW()),
  ('Protiv Zemlje u ime Neba', 'Mustafa Čengić', 15.00, '/images/knjige/96.webp', 'Posebnu pažnju javnosti Mustafa Čengić je izazvao knjigom Alija Izetbegović - jahač apokalipse ili anđeo mira. Njegova najnovija knjiga Protiv Zemlje u ime Neba nastavak je kritičke analize iracionalne i antibosanske vladavine Stranke demokratske akcije.', 1, 0, NOW(), NOW()),
  ('Atelje na broju 19', 'Jasna Šamić', 25.00, '/images/knjige/97.webp', 'Svaki portret je jednim dijelom i autoportret slikarev u smislu neke grafologije u kojoj se izražava slikar, u smislu izbora stava, jer svaki čovjek ima svoj stav i svoje držanje koji ga izvanredno određuju i razlikuju od drugih ljudi. Mnogi griješe, pogotovo fotografi kad namještaju čovjeka, izvještačuju ga...', 1, 0, NOW(), NOW()),
  ('Zvuci kaldrme', 'Ildiza Hadžajlić Kuburović', 20.00, '/images/knjige/1024.webp', 'Prvi deo knjige predstavlja omaž jednom detinjstvu i mladosti provedenim u Sjenici. Nostalgična, topla atmosfera izbija iz svake stranice, evocirajući sećanja, ukuse, mirise, teksture detinjstva. Kroz priče o mestima koja su iscrtala mapu jednog života (korzo, pekara, obućarska radnja, bakina kuća, osnovna škola...) naziru se obrisi jednog vremena i jedne lične istorije. Na mahove folklorno, arhaično, romantizovano, kao da se dešavalo pre mnogo više od četrdesetak godina, kada je autorka te stvari i doživljavala. Drugi deo knjige je takođe sentimentalan, samo je emocija drugačija. Punija i zrelija. U pitanju je period života kada se autorka, trudna, seli u Holandiju sa svojim suprugom i provodi punih osam godina u azilu. Bez imalo samosažaljenja i upadanja u ulogu žrtve, uspeva da nam dočara utisak kako je to biti azilant 2000. godine.', 1, 0, NOW(), NOW()),
  ('Sarajevo, vrijeme bluza', 'Vladimir Šimunović', 35.00, '/images/knjige/1022.webp', 'Sarajevo, vrijeme bluza je knjiga sjećanja na događanja o jednoj maloj ratnoj bolnici u jednom strašnom ratu. To nije knjiga o borbama i masakrima, razaranjima i strahotama, o podvizima i herojstvu. Ovo su tek sjećanja na jedan period u našim životima, poslije koga se Zemlja počela okretati u suprotnom smjeru, a svijet i ljudi su dobili nova svojstva, nove vrijednosti i nove boje.', 1, 0, NOW(), NOW()),
  ('Kriza religije', 'Ivan Cvitković', 30.00, '/images/knjige/1023.webp', '- Kada je Pablo Neruda rekao prijatelju da piše novu knjigu, upitao ga je: O čemu se radi u njoj? Odgovor je bio: U knjigama se uvijek radi o istome - uvijek pišem istu knjigu. I ja uvijek pišem istu knjigu: o religiji, naciji, nacionalizmu. Oavj put s naglaskom na krizu religije.', 1, 0, NOW(), NOW()),
  ('(NE) MIRNA BOSNA', 'Željko Ivanković', 20.00, '/images/knjige/knjiga1.webp', 'Između korica knjige „(Ne)mirna Bosna“, Željka Ivankovića, na gotovo dvije stotine stranica smješteno je 40 kolumni. Knjigu „(Ne)mirna Bosna“ preporučujemo kao vrijednu čitanja jer ona i po svojoj formi, dakle kolumnističkoj, odgovara i duhu postomoderne kojim smo, neovisno što o njemu mislili, daleko više obilježeni nego što to slutimo ili smo spremni priznati. Autor na nepristran i kritički način a na temelju konkretnih pojava daje preciznu dijagnozu stanja bosansko-hercegovačkog društva, dakako dijagnozu koja je gorka i mučna, no upravo zbog toga i nužna želimo li učiniti nešto da ona u neko dogledno vrijeme izgleda drugačije.', 1, 0, NOW(), NOW()),
  ('Al tempo: psychografia pseudologiae phantastica', 'Esad Bajtal', 20.00, '/images/knjige/knjiga2.webp', 'Enciklopedijska zaokruženost Bajtalovih znanja dopušta teške sudove od kojih se ježi koža.', 1, 0, NOW(), NOW()),
  ('Atentat ili drama u Sarajevu, 28. juni 1914.', 'Grupa autora', 20.00, '/images/knjige/knjiga3.webp', 'Atentat ili drama u Sarajevu, 28. juni 1914. - Assasination or drama inSarajevo, 28. of June 1914, skraćeno izdanje knjige na bosanko-engleskom jeziku.', 1, 0, NOW(), NOW()),
  ('Balkanska priča', 'Duško Anđić', 20.00, '/images/knjige/knjiga4.webp', 'Kratki izvod iz romana: “Ovo mi se događa već treći put. Prvi put je to bilo prije četiri godine, kada sam išao za Samaru. Pa onda, dvije godine - ništa, a često sam putovao. I, evo sada, ove godine već drugi put. Da to nije neki znak? Nekakvo upozorenje?”', 1, 0, NOW(), NOW()),
  ('Baš Baščaršija', 'Nada Salom', 25.00, '/images/knjige/knjiga5.webp', 'Baščaršija je ljubav sa kojom se rađa svaki stanovnik ovog grada i koja raste sa svakim novim izlaskom sunca i danom koji se rađa. Baščaršija je dio života, utkana u svaku našu poru i neizbrisivo upisana u svaku našu uspomenu. Onaj ko je upozna ostaje zaljubljen u nju do kraja života i nikada je ne zaboravi. Baščaršija je djelo čovjeka i naše najljepše naslijeđe koje smo dužni da ljubomorno čuvamo i štitimo kako bismo je još bolju ostavili u amanet našoj djeci i svim budućim generacijama. - Nada Salom', 1, 0, NOW(), NOW()),
  ('Bosanska Heraldika', 'Grupa autora', 10.00, '/images/knjige/knjiga6.webp', 'Heraldika je srednjovjekovna po porijeklu i vezana je za identifkaciju. To je sistem i identifciranja osoba posredstvom nasljednih znamenja postavljenih na štit, sistem koji je nastao u zapadnoj Europi u srednjem vijeku. Pravilno primijenjena, heraldika je veoma egzaktan i precizan sistem identifkacije daleko dostatniji nego bilo koji sistem imena; heraldički pečat mnogo je veće vrijednosti nego puki potpis jer daje bogatstvo detalja o osobi. U bosanskom slučaju dosad je istraživan pretežno kulturološki aspekt - kulturni utjecaji na srednjovjekovnu Bosnu. Genealoško i politološko značenje heraldičkih amblema na bosanskim grbovima u istraživanjima je tek načeto. Povijesno zasvjedočeni arhivi nekih srednjovjekovnih bosanskih porodica - Hranića-Kosača, Hrvatinića, Pavlovića i Kotromanića - i raznošenje isprava u godini pada bosanske države 1463. čije posljedice je ispravom izdanom u Rimu 11. VII. 1469. pokušao ublažiti papa Pavao II., tu pretpostavku čine još ozbiljnijom. Koliko se tog neprocjenjivog kulturnog blaga tada prelilo preko granica Bosne teško će ikad biti ustanoviti, ali je sasvim sigurno da povijest bosanske srednjovje-kovne emigracije još uvijek čeka na svoje historiografsko pero.', 1, 0, NOW(), NOW()),
  ('Čitanje Bosne i Hercegovine - Putevi i studije iz godina 1892.-1896.', 'Ludvig Kuba', 45.00, '/images/knjige/knjiga7.webp', 'Ludvik Kuba je poznati češki umjetnik, skoro renesansne širine interesovanja: bio je, među ostalim, slikar, pisac te etnomuzikolog. Zabilježno je da je Kuba bio nevjerovatno svestran muzičar, orguljaš, pijanist, violinist, harmonizator, muzički teoretičar, slikar, crtač, pisac, publicista, predavač i izdavač vlastitih djela.', 1, 0, NOW(), NOW()),
  ('Diplomatija bez protokola - Prvi dio', 'Slobodan Stajić Elefterios', 20.00, '/images/knjige/knjiga8.webp', 'Rukopis uglednog putopisca i publiciste Slobodana Stajića „Diplomatija bez protokola“ (u dva dijela) prezentuje 39 intervjua, objavljenih u „Oslobođenju“ u periodu od 1996. do 2007. godine, kao i mnogo zanimljivih storija iz svijeta diplomatije, vezanih kako za BiH tako i svijet. Intervjui su uglavnom sa uglednim diplomatama koji su nekada službovali u Bosni i Hercegovini, ali i sa četiri šefa diplomatije, kao i sa dvojicom nekadašnjih predsjednika, turskim Sulejmanom Demirelom i bugarskim Petrom Stojanovim, te sa jednom od najpoznatijih istoričara, Britancem Džasperom Ridlijem. U faktografskom dijelu prve knjige nabrojani svi generalni sekretari UN kao i neobične sudbine nekih od njih, zatim svi visoki predstavnici u BiH , kao i svi šefovi diplomatije BiH, te dvanaest ambasadora iz BiH, koji su se zatekli na mjestu veleposlanika neposredno prije raspada Jugoslavije.', 1, 0, NOW(), NOW()),
  ('Elektronička špilja', 'Predrag Finci', 20.00, '/images/knjige/knjiga9.webp', 'Fincijeva Elektronička špilja je knjiga o suvremenim medijima. U ovoj knjizi riječ je o problemima koji prate medije, od pitanja porijekla novih, elektroničkih igračaka, preko problema svakodnevnog komuniciranja i informiranja, do stvaranja novih mitova, medijske slave, reklame kao nove umjetnosti i pitanja funkcije umjetnosti u elektroničkim medijima.', 1, 0, NOW(), NOW()),
  ('Epistolarna simfonija', 'Wolfgang Amadeus Mozart', 20.00, '/images/knjige/knjiga10.webp', 'Knjiga pisama Wolfganga Amadeusa Mozarta Epistolarna simfonija koju je ovih dana izdala IK Rabic art Sarajevo peto je izdanje te zanimljive knjige.', 1, 0, NOW(), NOW()),
  ('Evlija Čelebija ponovo među nama', 'Enver Enko Mehmedbašić', 15.00, '/images/knjige/knjiga11.webp', 'Enko Mehmedbašić je ne samo najbolji već i daleko namoderniji bosansko hercegovački humoristički satirični pisac.Nadasve jedna visoko književno artikulisana i tipično sarajevska kombinacija vedrine, melanholije, privrženosti malom čovjeku i one zoščenovske čežnje za lijepim. U njegovom humorističnom i satiričnom pogledu na svijet ima i prave mudrosti, mudrosti da se duhom i humorom premoste, prevaziđu i savladaju silne neprijatnosti, gluposti i ograničenosti svijeta kojim putujemo, vremena u kome živimo.Ovo je izbor koji će ponovo oduševiti čitalačku publiku, kako dobrodušnim humorom, tako i sjajnim stilom jednog neponovljivog romantika koji je dokazao ne samo da je humor lijek za dušu, već i da su putopisi najkreativniji dio novinarstva, koji spaja žurnalizam i književnost.', 1, 0, NOW(), NOW()),
  ('Fojnički grbovnik', 'Vinko Falak', 99.00, '/images/knjige/knjiga12.webp', 'I pored relativno obimne literature koja je tokom posljednjih stotinu i vise godina sirila spoznaje o bosanskoj srednjovjekovnoj heraldici, njezino stanovno vredovanje jos uvijek je povojima i zato svako novo otkrice, novi metodoloski pristup ili pojava znanstvenih djela ohrabruje zakljucak o potrebi svestranijih istrazivanja ovog vaznog segmenta bosanskog srednjovjekovlja...', 1, 0, NOW(), NOW()),
  ('Fotelja za više osoba', 'Enver Enko Mehmedbašić', 15.00, '/images/knjige/knjiga13.webp', 'Enko Mehmedbašić je ne samo najbolji već i daleko namoderniji bosansko hercegovački humoristički satirični pisac.Nadasve jedna visoko književno artikulisana i tipično sarajevska kombinacija vedrine, melanholije, privrženosti malom čovjeku i one zoščenovske čežnje za lijepim. U njegovom humorističnom i satiričnom pogledu na svijet ima i prave mudrosti, mudrosti da se duhom i humorom premoste, prevaziđu i savladaju silne neprijatnosti, gluposti i ograničenosti svijeta kojim putujemo, vremena u kome živimo.Ovo je izbor koji će ponovo oduševiti čitalačku publiku, kako dobrodušnim humorom, tako i sjajnim stilom jednog neponovljivog romantika koji je dokazao ne samo da je humor lijek za dušu, već i da su putopisi najkreativniji dio novinarstva, koji spaja žurnalizam i književnost.', 1, 0, NOW(), NOW()),
  ('Hiljadu i druga noć', 'Zlatko Dizdarević', 30.00, '/images/knjige/knjiga14.webp', 'Knjiga, objavljena u okviru Smeđe biblioteke, donosi autorovo iskustvo višegodišnjeg boravka u zemljama Bliskog istoka, njegove poglede na društveno-političku situaciju u tim zemljama i odnose s ostalim zapadnim zemljama, te život običnih ljudi.', 1, 0, NOW(), NOW()),
  ('Izabrana djela 1-6 Enver Enko Mehmedbašić', 'Enver Enko Mehmedbašić', 60.00, '/images/knjige/knjiga15.webp', '„Fotelja za više osoba“ i „Kap tinte“ obuhvata sjajne humorističke priče iz autorove sehare, kao i „Evlija Čelebija ponovo među nama“, „Jugohauzen“ i „Staro ogledalo“, dok nas putopisna knjiga „Pravim se Englez“ vodi do dalekih prostranstava mnogih evropskih država, kao i Južne i Centralne Amerike. Dok nas u prve četiri knjige, svojim vrcastim humorom, autor duhovitošću opušta do beskraja, dotle nas putopisnom, kao duhovni vodič, šarmantno upoznaje sa mnogim zanimljivim predjelima i običajima, od ekscentričnih Engleza u Hajd parku, temperamentnih Španjolaca na koridi, lisabonskih osmijeha, zatim praških noći i Bosanaca u Budimpešti, sve do zanosne i izazovne plovidbe Atlantikom uz blagoslov Neptuna, meksičke fieste, „Pozlaćenih priča“, „Paklenih vrata raja“ i panamskih susretanja.', 1, 0, NOW(), NOW()),
  ('Janus sa tri lica', 'Slobodan Stajić Elefterios', 20.00, '/images/knjige/knjiga16.webp', 'Evo knjige Slobodana Stajića koja nije kao njegove prethodne knjige. Ili je to samo malo, u stilu i osnovnom pristupu. E, a sada nam Stajić stiže sa ovim Janusom s tri lica, koji otkriva onu drugu stranu medalje svijeta koji je obilazio, onu medalju koju je svjesno ili nesvjesno ostavljao po strani, čuvajući je za ovu posljednju knjigu. Pa, ako i prihvatim njegove riječi da su putovanja kao spomenari, ovaj spomenar više nije romantika, niti bijeg u antiku, nego hod po mukama, patnjama i krvlju kojom je zaliven onaj isti svijet antike iz njegovih putopisa. A to je najviše svijet Srednjeg istoka, istočnog Mediterana, Grčke i Turske, od kojih je i prvu i drugu posjetio tridesetak puta. A nije mogao da ostavi po strani ni svoju Bosnu i Hercegovinu. Stajić ovu drugi stranu medalje okreće polako, obazrivo, kao da se plaši ponora u koji su svijet koji opisuje gurnule svjetske sile. Kao da hoće da zavara čitaoca koji očekuje da će mu iz knjige progovarati samo sirene, on ih u tako novo stanje uvodi pričom o zanosnoj Lori koja na nekoj bajkovitoj sicilijanskoj obali čita Andrićevu „Prokletu avliju“. On se pomalo nad njenom zanosnom pojavom ispovijeda, pa joj prilazi pažljivo, jer naš Slobo ne pripada momcima koji su napadni prema ženama – tako kaže – nego je zatajan... Eto, tako počinje Stajić svoju novu knjigu, a onda se sruči i čitaoca suoči s realnošću sadašnjice, a ne mitovima i sanjarijama iz prošlosti.', 1, 0, NOW(), NOW()),
  ('Jugohauzen (dobra stara vremena)', 'Enver Enko Mehmedbašić', 15.00, '/images/knjige/knjiga17.webp', 'Enko Mehmedbašić je ne samo najbolji već i daleko namoderniji bosansko hercegovački humoristički satirični pisac.Nadasve jedna visoko književno artikulisana i tipično sarajevska kombinacija vedrine, melanholije, privrženosti malom čovjeku i one zoščenovske čežnje za lijepim. U njegovom humorističnom i satiričnom pogledu na svijet ima i prave mudrosti, mudrosti da se duhom i humorom premoste, prevaziđu i savladaju silne neprijatnosti, gluposti i ograničenosti svijeta kojim putujemo, vremena u kome živimo.Ovo je izbor koji će ponovo oduševiti čitalačku publiku, kako dobrodušnim humorom, tako i sjajnim stilom jednog neponovljivog romantika koji je dokazao ne samo da je humor lijek za dušu, već i da su putopisi najkreativniji dio novinarstva, koji spaja žurnalizam i književnost.', 1, 0, NOW(), NOW()),
  ('Kafe na tri čoška', 'Nedeljko Opančić', 20.00, '/images/knjige/knjiga18.webp', 'Ovo je najneozbiljnija ozbiljna knjiga koja se može pročitati i zato je svima toplo preporučujemo da je izvade iz cekera. “Kafe na tri ćoška” knjiga je i omaž tekstopiscima, glumcima i rediteljima Miši Miliću, Miši Bušiću, Nebojši Čelikoviću, Žari Turubatoviću, Zlatku Sesaru…Zamislite kako sjedite u Kafeu na tri ćoška a za susjednim stolom glasno negoduju protiv Predsjedništva, Vijeća Ministara, selektora, Dodika…!!! Za drugim stolom sjede četvorica policajaca i smješkaju se na sve to!? Klasična sarajevska idila kafanskih ublehaša. Autor je as u t i satiričar koji sve vidi i kaže na svoj način. On ne imenuje, ali čitalac tačno zna ko stoji iz tog i tog političkog gafa, propusta, previda, as u i anomalija.', 1, 0, NOW(), NOW()),
  ('Ključ besmrtnosti', 'Hari Slipičević', 20.00, '/images/knjige/knjiga19.webp', 'Roman ‘’Ključ besmrtnosti’’ Harija Slipičevića, uzbudljiva je akcijska priča o opasnoj potrazi za misterioznom drevnom knjigom koja čuva tajnu vječnog života – ‘’Knjigom mrtvih’’. Vješto napisan roman prati Maca Lewita, profesora istorije iz New Yorka koji biva uvučen u rješavanje misterije oko jedne od najbolje čuvanih tajni na svijetu. Uzbudljiva i napeta radnja drži čitaoca u iščekivanju, stranicu za stranicom do samog kraja koji sadrži neočekivan obrat i otkriva sasvim nov pogled na istoriju našeg svijeta.', 1, 0, NOW(), NOW()),
  ('Kontra smjer', 'Željko Toprek', 10.00, '/images/knjige/knjiga20.webp', 'Kontra smjer, knjiga poezije autora Željka Topreka', 1, 0, NOW(), NOW()),
  ('Križ na brdu', 'Slavko Hadžić, Joshua Irby', 20.00, '/images/knjige/knjiga21.webp', 'Osobna, istorijska i biblijska potraga za pravim značenjem kontroverznog simbola. U knjizi, autori Hadžić i Irby tragaju za značenjem križa. Pridružite se potrazi i kroz zanimljivu životnu priču, istoriju i Bibliju dođite do otkrića pravog značenja tog kontroverznog simbola.', 1, 0, NOW(), NOW()),
  ('Majke Srebrenice + CD-e', 'Josip Pejaković', 50.00, '/images/knjige/knjiga22.webp', 'Knjiga Majke Srebrenice je spoznaja da svijet nije crno-bijeli! Između toga postoji istina koja još uvijek nije dokraja otkrivena! „Majke Srebrenice“ novo djelo Josipa Pejakovića moralna je poruka i pouka ne samo ove priče, nego cjelokupnog Pejakovićevog umjetničkog, glumačkog, pozorišnog, društvenog i ljudskog angažmana, jer on sasvim dobro i „u ime naroda“, razlikuje one koji istoriju stvaraju od onih koji je trpe. I na strani je ovih drugih, pred kojima je empatički otvoren i spreman na ljudsku, racionalnu pobunu, u ime, i protiv, krvavim nasiljem zatrvenog bosanskog zajedništva bez koga nema nadilaženja planski nametnutog gaženja ljudskog dostojanstva. Josip Pejaković skida prašinu sa vječnog ogledala jednoće i jedinstvenosti svega. Ono je oduvijek brušeno i polirano svuda. Možda najteže, najbolnije i najsladje u Bosni!', 1, 0, NOW(), NOW()),
  ('Mario Mikulić - crteži', 'Željko Ivanković', 60.00, '/images/knjige/knjiga24.webp', 'Od ljudi Mario ne zna ljepših pejsaža zapisao je davne 1973. godine pjesnik Izet Sarajlić o svom prijatelju Mariju Mikuliću, poznatom slikaru i jednom od najčuvenijih portretista sa prostora bivše Jugoslavije. Urednik monografije je Željko Ivanković koji za crtež Marija Mikulića kaže da je uglavnom brz, reduciran, temperamentan te da se upravo u njegovom crtežu vidi istinitost izreke Edgara Degasa Crtež nije oblik, to je način gledanja oblika.', 1, 0, NOW(), NOW()),
  ('Mario moj otac', 'Goran Mikulić', 20.00, '/images/knjige/knjiga25.webp', 'Otac je Mario Mikulić (1924-1991), koji potpisuje bogat opus slika koji i danas oplemjenjuju naše življenje, s motivima ulica, prirode, žive i nežive, ali i nizom likova, ličnosti, figura zaustavljenih u vremenu. Sin je Goran Mikulić, diplomirani arhitekta, koji danas projektuje osobenu izdavačku produkciju. O svjedočanstvu u ovoj jedinstvenoj knjizi, koja je istovremeno bio, foto i likovna monografija, pjesnik i novinar Mišo Marić bilježi u pregovoru da je Goran, građevinac po obrazovanju, a izdavač po ljubavi, sjeo na slikarevu stolicu pred štafelajem, a on na onu ispred gdje su neprikosnovenom maestru portreta strpljivo pozirali Josip Broz, Ivo Andrić, Meša Selimović, Skender Kulenović, Kiko Sarajlić...; znano i neznano a drago Sarajevo i hodočasnici u njega:', 1, 0, NOW(), NOW()),
  ('Mostar moj grad', 'Hamica Ramić', 20.00, '/images/knjige/knjiga26.webp', 'Ovo je svojevrsna čitanka, ovo je skup izvanrednih radova 22 autora koji opisuju pravu recepturu grada, življenja u ovom gradu. Mislim da nije problem da se ta receptura uzme i primjeni u nekim novim vremenima, kako bi oblikovali život dostojan čovjeka - Hamica Ramić', 1, 0, NOW(), NOW()),
  ('O kolodvoru i putniku', 'Predrag Finci', 15.00, '/images/knjige/knjiga27.webp', 'Znao sam mnoge gradove, obišao mnoga mjesta, a samo sam jedno smatrao svojim. Ne toliko zato što sam se u njemu rodio (to i nije toliko važno), nego zato što sam u njemu odrastao (što je presudno), pa sam sve mislio da mi „prirodno pripada. Moj Grad: Onaj koji je bio moja java, a postao moj san, onaj u kome su se rađali moji snovi i razoriše moje jave. Onaj koji se pretvorio u priču i sliku. U pejzaž s ranom', 1, 0, NOW(), NOW()),
  ('O poeziji, pticama i drugim varkama', 'Nedžad Ibrahimović', 20.00, '/images/knjige/knjiga28.webp', 'Ono što ovu knjigu, po meni, čini izuzetnom i opet po mom sudu, obaveznim štivom u modernoj bh. prozi je - osim fragmentarne forme koja vjerno preslikava atomiziranost američkog društva - poetičnost i preciznost s kojom Nedžad analizirajući jezik i njegovu svakodnevnu upotrebu i funkciju secira socijalno i emotivno tkivo na individualnom nivou. Tek tada je, i golim okom vidljivo da je cijena za totalnu personalnu slobodir masovna usamljenost: da je slobodna tržišna utakmica eufemizam za brutalni ekonomski darvinizam; da je Vasa Ladački američki sindrom, a ne usamljeni banatski slučaj.', 1, 0, NOW(), NOW()),
  ('Odgovor džihadu', 'Nabeel Quereshi', 20.00, '/images/knjige/knjiga29.webp', 'Nabel Qureshi, autor bestselera New York Timesa, donosi nam ovaj lični, izazovni, učtivi odgovor na mnogo pitanja o džihadu, o usponu IDIL-a i islamskom terorizmu. Ostavljajući po strani nagađanja i nadmetanja, Odgovor džihadu, nam daje uvid u ptanja na koja svi pokušavamo pdgovoriti. Šta je džihad? Ko su istinski muslimani? Da li je islam vjera mira. I možda najvažnije: kako da idemo naprijed?', 1, 0, NOW(), NOW()),
  ('Palestinska Nakba', 'Hajrudin Somun', 40.00, '/images/knjige/knjiga31.webp', 'Palestinska Nakba je kombinacija naučnog pristupa i polustoljetnog ličnog praćenja palestinsko-izraelskog konflikta. Do sada na južnoslavenskim jezicima nije bilo cjelovitog pregleda tog kompleksa, pa sam se trudio da to učinim. Na čitaocima i stručnjacima je da kažu koliko sam uspio, ali mi je drago što je jedan od recenzenata, Dženita Karić, magistrica palestinske književnosti, pogodila moju ideju vodilju kad je napisala: Knjiga Palestinska Nakba ukazuje na to da osnovni problem palestinskog pitanja nije religija, kultura ili etnicitet, već borba za zemlju zbog čega nastaju čak i sukobljeni historijski narativi. Historija, odnosno njezine različite interpretacije, podređena je toj borbi koja je proizvela ubijanja, progone i sveopću patnju Palestinaca mnogo prije same Nakbe ili katastrofe.', 1, 0, NOW(), NOW()),
  ('Plave kacige i crno tržište', 'Peter Andreas', 15.00, '/images/knjige/knjiga32.webp', 'Ova hrabra, provokativna knjiga obavezna je literatura za svakog koga zanimaju dileme humanitarne podrške ratu. Peter Andreas opisuje manjkavi međunarodni poduhvat dostave humanitarne pomoći, koji je doprinio da se produži najduža opsada u savremenoj povijesti, i to tako da je omogućio da se obogate kriminalci i ratni profiteri. Jedino ako shvatimo zašto se i kako takve stvari događaju možemo se nadati da ćemo ih moći spriječiti u budućnosti. Richard Holebrooke Plave kacige i crno tržiste je potpuno fascinantna knjiga. Fokusirana je, izbalansirana, originalna, dobro istražena i promatra stvarne događaje iz opsade Sarajeva pristupom odozdo prema gore. Andreas gotovo na svakoj stranici uništava licemjerne, opšeprihvaćene klišee John Mueller, Ohio State University', 1, 0, NOW(), NOW()),
  ('Povijest est magistra vitae', 'Dubravko Lovrenović', 20.00, '/images/knjige/knjiga33.webp', 'Ovo je knjiga polemika koje se već dva desetljeća, a u širem smislu i gotovo dva stoljeća, vode u BiH, u tim se polemikama sukobljavaju različiti politički koncepti u BiH. Autor mita o predaji djedovskog štapa šejhu mevlevijskog bratstva ignorira ove zakonomjernosti u povijesti konverzija, te bi od štapa djeda Crkve bosanske napravio most preko kojeg su bosanski krstjani s jedne prešli na drugu obalu konfesionalnog identiteta. Bez minimuma znanstvene argumentacije i intelektualne odgovornosti, jednom plasiran u javnost mit o štapu djeda Crkve bosanske nastavio je svoj život proizvodeći po toj istoj izokrenutoj logici teško mjerljivu društvenu štetu. Pretočen u bošnjacku političku mitologiju bogumilski mit svakim danom poprima sve jasnije populističke dimenzije uz afirmaciju herojske (epske) historijske svijesti, kojoj je za vlastiti opstanak prijeko potreban povijesni neprijatelj.', 1, 0, NOW(), NOW()),
  ('Pravim se englez', 'Enver Enko Mehmedbašić', 15.00, '/images/knjige/knjiga34.webp', 'Enko Mehmedbašić je ne samo najbolji već i daleko namoderniji bosansko hercegovački humoristički satirični pisac.Nadasve jedna visoko književno artikulisana i tipično sarajevska kombinacija vedrine, melanholije, privrženosti malom čovjeku i one zoščenovske čežnje za lijepim. U njegovom humorističnom i satiričnom pogledu na svijet ima i prave mudrosti, mudrosti da se duhom i humorom premoste, prevaziđu i savladaju silne neprijatnosti, gluposti i ograničenosti svijeta kojim putujemo, vremena u kome živimo.Ovo je izbor koji će ponovo oduševiti čitalačku publiku, kako dobrodušnim humorom, tako i sjajnim stilom jednog neponovljivog romantika koji je dokazao ne samo da je humor lijek za dušu, već i da su putopisi najkreativniji dio novinarstva, koji spaja žurnalizam i književnost.', 1, 0, NOW(), NOW()),
  ('Putevi znanja - Moj put', 'Mičo Jančev', 20.00, '/images/knjige/knjiga35.webp', 'U knjizi autor na zanimljiv način opisuje svoju stručnu i profesionalnu karijeru – od prvog zaposlenja u Vazduhoplovnom zavodu „Orao“ u Sarajevu 1968. godine, do početka rata u Bosni i Hercegovini. Knjiga, po predmetu koji obrađuje, pripada kategoriji stručne literature. Stvarana je u neposrednoj praksi, kao rezultat direktnog suočavanja s promjenama u više proizvodnih organizacija i nudi odgovor na pitanje: Kako se pripremiti za suočavanje sa problemima koje nose tehnološke promjene? Knjiga je bogata stručnim šemama i tabelama, kao i sintetizovanim pregledima zanimljivih podataka. Ali, kako sam autor kaže, njegova je namjera bila da napiše stručnu knjigu koja neće biti dosadna za čitanje, koja će imati „dušu“; obiluje velikim brojem „živih primjera“ iz njegove prakse – više od 200 konkretnih ličnosti...', 1, 0, NOW(), NOW()),
  ('Sabrana djela 1-6/ Fra Petar Anđelović', 'Fra Petar Anđelović', 60.00, '/images/knjige/knjiga36.webp', 'Fra Petar Anđelović, bivši provincijal Bosne srebrene, preminuo je u Sarajevu 14. januara u 72. godini. Petar Anđelović, rođen je u mjestu Boće kod Brčkog 9. decembra 1937. Objavio je niz knjiga i publicističkih radova. Između ostalog: Žena u Crkvi poslije Drugog vatikanskog sabora i Selidba Ramljaka. Radovi s povijesno-teološkog simpozija u povodu 300. obljetnice odlaska franjevaca i puka iz Rame u Cetinsku krajinu održanog na Šćitu 4. i 5. rujna 1987. godine, TEBIS, Sarajevo, 1998, 135-151, Mali brat kakva treba franjevačka zajednica, u: Verbi ministri et omnes creati cultor. (Zbornik u čast prof. Dr. Fra Vitomira Slugića u povodu 70 godina života ), Sarajevo 1998, 73-78., Od Franje učiti ljubiti crkvu - sv. Franjo, franjevci i hijerarhija, u: Spomen-spis. Povodom 90. obljetnice rođenja dr. Fra Ignacija Gavrana, Zagreb 2004, 9-15. Vjerni Bogu vjerni Bosni, Franjevci na prijelazu u treće tisućljeće, Stvarnost(i) okom vjernika.', 1, 0, NOW(), NOW()),
  ('Sarajevo atentat - 100 godina poslije', 'Željko Ivanković', 89.00, '/images/knjige/knjiga37.webp', 'Sarajevski atentat, koji je po zlu ime Sarajeva upisao u povijest, stotinu godina poslije, mjesto je i vrijeme, topos je komemoriranja svega onoga što je povijesno ili mitski, društveno ili politički, stvarnosno ili umjetnički… značio ili mogao značiti. Potpuno otvoreni, kako smo to i naslovom sugerirali, za svako relevantno promišljanje toga povijesnog čina i svih njegovih stvarnih ili potencijalnih reperkusija, za tu smo prigodu pozvali neka od, po našem odabiru, najrelevantnijih imena iz regiona i zemalja s kojima je BiH dijelila sudbinu pripadanja Austro-Ugarskoj… Knjiga koju držite ili ćete držati u rukama - produkt je te želje. Ambiciozne, ali ne i pretenciozne. Radove onih koji su odgovorili ovom izazovu donosimo u ovoj knjizi, ne želeći pritom ni postavljati pitanja, ni davati odgovore, nego tek, obilježavajući godinu u kojoj je glavni grad BiH zakoračio u svjetsku povijest, iznova, makar i u malome, misliti stoljeće koje je otada prošlo, njegove mijene i nas u njemu, u njima. Otuda ova knjiga donosi raznolike historiografske poglede, kao mogući ram za sliku jednog povijesnog čina, te literarizaciju nekih njegovih aspekata kao dar čitateljskoj imaginaciji onih koji su svjesni da su knjige tu da bi bile čitane, a ne da bi rješavale sudbinska pitanja svijeta. Fotomonografija je, osim tekstova eminentnih autora - Ivo Banac, Ivo Goldstein, Latinka Perović, Filip David, Svetislav Basara, Milan Zemko, Miljenko Jergović, ilustrirana foto-dokumentacijskom građom.', 1, 0, NOW(), NOW()),
  ('Staro ogledalo', 'Enver Enko Mehmedbašić', 20.00, '/images/knjige/knjiga38.webp', 'Enko Mehmedbašić je ne samo najbolji već i daleko namoderniji bosansko hercegovački humoristički satirični pisac.Nadasve jedna visoko književno artikulisana i tipično sarajevska kombinacija vedrine, melanholije, privrženosti malom čovjeku i one zoščenovske čežnje za lijepim. U njegovom humorističnom i satiričnom pogledu na svijet ima i prave mudrosti, mudrosti da se duhom i humorom premoste, prevaziđu i savladaju silne neprijatnosti, gluposti i ograničenosti svijeta kojim putujemo, vremena u kome živimo.Ovo je izbor koji će ponovo oduševiti čitalačku publiku, kako dobrodušnim humorom, tako i sjajnim stilom jednog neponovljivog romantika koji je dokazao ne samo da je humor lijek za dušu, već i da su putopisi najkreativniji dio novinarstva, koji spaja žurnalizam i književnost.', 1, 0, NOW(), NOW()),
  ('Stećci - Medieval Tombstone', 'Grupa autora', 10.00, '/images/knjige/knjiga40.webp', 'Stećci - Medieval Tombstones, skraćeno izdanje knjige na bosanko-engleskom jeziku.', 1, 0, NOW(), NOW()),
  ('Time Lapse', 'Midhat Ajanović', 20.00, '/images/knjige/knjiga41.webp', 'Midhat Ajanović Ajan je pisac, profesor filma, filmski autor i karikaturist, rođen u Sarajevu 1959. Diplomirao je novinarstvo u Sarajevu i učio animaciju u Zagreb filmu. Od 1994. živi u Göteborgu (Švedska), gdje je doktorirao s filmološkom tezom. Voditelj je odsjeka za animaciju i vizualne komunikacije na švedskom Sveučilištu West u Trollhättanu. Objavio je više knjiga raznih žanrova i na nekoliko jezika – sedam romana, od kojih su četiri objavljena u Hrvatskoj: ‘Jalijaš’, ‘Katapult’, ‘Salijevanje strave’ i ‘Portret nacrtan ugljenom i kišom’ te više djela iz povijesti i teorije animiranoga filma. Za svoj rad nagrađivan je na uglednim književnim i filmskim manifestacijama i izložbama diljem svijeta. Između ostaloga, dobio je i posebno priznanje za doprinos u proučavanju animacije koju dodjeljuje zagrebački Animafest. 2010. godine na Međunarodnom sajmu knjige u Göteborgu za roman ‘Portret nacrtan ugljenom i kišom’ dobiva Klas deWilderovu nagradu koja se dodjeljuje najboljem švedskom piscu useljeničkog podrijetla. ‘Time Lapse’ je Ajanovićev sedmi roman, koji nastavlja sjajni niz oslikavanja Bosne i Sarajeva spajanjem tradicije, povijesti i nadrealizma, specifičnom mješavinom borgesovskih slika. Ajanović-pisac stvara slike riječima jednako kao što ih može stvoriti stripom, karikaturom i animacijom. Povijesni likovi se susreću s imaginarnim, jednako uvjerljivih životnih priča, da na kraju postaje potpuno nevažno postoje li ili ne. Uostalom i sam autor kaže: Knjiga mora biti istinita čak i kada je sve u njoj laž.', 1, 0, NOW(), NOW()),
  ('Trpi li Bog zulum', 'Ivan Lovrenović', 20.00, '/images/knjige/knjiga42.webp', 'U svojim vanrednim knjigama kakve su Labirint i pamćenje i Bosanski Hrvati, Lovrenović je realizirao specifični oblik diskursa kulturnopovijesnog eseja, postavljajući neku vrstu osnove ovdašnjoj kulturološkoj esejistici i analizirajući pri tom ambivalentni, hibridni, dijalektički utemeljen bosanskohercegovački kulturnopovijesni identitet. U knjigama od Ex tenebrisa do Trpi li Bog Zulum on tematizira neposrednu krvavu bosansku prošlost i tranzicijski prezent iz pozicije političkoga hroničara, analitičara ideologija, komentatora socioloških i kulturoloških prevrata i transformacija, neprestano se pitajući kako je moguće misliti bosanskohercegovački susret/ sudar različitih kulturnih, nacionalnih, političkih, socioloških i čitavog niza drugih identiteta i identiranih procedura. Ključne formule iz kojih in primislja aktualitet historijskih i političkih zbivanja mogle bi se opisati pojmovima dekonstrukcijskog modela analize.', 1, 0, NOW(), NOW()),
  ('1993. Prevare, zablude , istine', 'Stjepan Šiber', 25.00, '/images/knjige/1000.webp', 'Stjepan Šiber bio je vojnik starog kova. Energičan, hrabar, odlučan i „bez dlake na jeziku“ - a upravo ga je potonja osobina u životu koštala mnogo čega, kažu oni koji su dobro poznavali časnog generala. General Stjepan Šiber ispisao je stranice svojim nezaboravljenim sjećanjima svog ratnog dnevnika darujući mu naslov: „1993. Prevare, zablude, istina“… Sjećaju se mnogi njegovih izgovorenih riječi kada je odgovorio jednom prilikom, u svom stilu, „dušebrižnicima“ nacionalne svijesti… “Slučajno sam se rodio kao Hrvat…” General Stjepan Šiber do svog posljednjeh daha i posljednjeg ovozemaljskog dana svog života vjerovao je u jedinstvenu Bosnu i Hercegovinu.', 1, 0, NOW(), NOW()),
  ('Besjede mrtvih - Od Pandore do Janusa', 'Slobodan Stajić', 20.00, '/images/knjige/1001.webp', 'Knjiga Besjede mrtvih predstavlja crnu i bolnu listu proizvoda ljudske negacije, izopačenosti, otuđenosti, prokletstva, zla, kvarnosti, nehaja, neodgovornosti, ludosti... Sve je ovo svuda oko nas, ne možemo da ih izbjegnemo dok nas fatalno okružuju i čine nas nesrećnim, očajnim. Kroz cijelu knjigu Stajić veli: „Da pamet stane“, „Da čovjek vrisne do neba“, „Zar on nema duše“, „Zar nema nikakvih moralnosti i skrupula“, „Nikada mi neće biti jasno kako je bilo moguće“, „To čovjeka ne ostavlja nimalo ravnodušnim“, „i tako redom i tako redom...“ Knjiga je prepuna nimalo bezazlenih pitanja od kojih zavisi moralni spas naše oboljele planete koja odnosi dnevno u smrt 18 hiljada mališana. U ovoj knjizi koja boli i opominje, autor pokušava bezuspješno razumjeti „...koji to porivi čovjeka tjeraju na nečovještvo, pogotovo ljude iz civilizovanog svijeta. Otkud toliko paklenika, neljudi i bezdušnika?“', 1, 0, NOW(), NOW()),
  ('Chief Drvena Noga', 'Rizah Pašalić', 15.00, '/images/knjige/1002.webp', 'Dječji roman Chief drvena noga sarajevskog advokata i pisca Rizaha Pašalica nije ratni roman ni tematski, ni po vremenu događanja a ipak je, veoma suštinski, vezan za ratno vrijeme. Nastajao je, naime, u vremenu između 1992. i 1994-95. na Grbavici (gdje je Pašalica zatekao rat) u nevelikim slobodnim vremenskim prostorima između najrazličitijih, i dnevnih i noćnih, prinudnih radova.', 1, 0, NOW(), NOW()),
  ('Fighting Cybercrime: The International legal and institutional framework and B&H', 'Dr. Arben Murtezić / Andrea Dizdarević, mag.', 35.00, '/images/knjige/1003.webp', '„Borba protiv kompjuterskog kriminala: međunarodni pravni i institucionalni okvir i Bosna i Hercegovina“ Riječ je o dvojezičnom izdanju, čiji je izvorni tekst napisan na engleskom jeziku te preveden na naš jezik. Predgovor je napisao dr. Paul Norman, dekan Institute for Criminal Justice Univerziteta u Portsmouthu, jedne od najuglednijih institucija te vrste u Velikoj Britaniji. Recenzenti su profesori našeg fakulteta: prof. dr. Haris Halilović i prof. dr. Eldan Mujanović. Knjiga, između ostalog, obuhvata analizu tipologije djela, izazova u izgradnji adekvatnog sistemskog odgovora, identificiranje i evaluaciju rada relevantnih međunarodnih i domaćih institucija, te osnovna pitanja digitalne forenzike. Poseban akcenat je na pravnom okviru iz aspekta usklađenosti domaćih propisa i međunarodnih dokumenata. Knjiga je rezultat sveobuhvatnog istraživanja koje, pored primarnog istraživanja provedenog u pravosuđu i agencijama za provođe nje zakona u Bosni i Hercegovini, obuhvata i bibliografiju od preko 250 naslova.', 1, 0, NOW(), NOW()),
  ('Grad oslikan balonima i kišom / Antologija savremene slovenačke ženske poezije', 'prevod: Dejan Tešić', 10.00, '/images/knjige/1004.webp', 'Ovo izdanje je obuhvatilo izbor iz najrecentnijih zbirki poezije jedanaest pjesnikinja različitih poetičkih izraza i godišta (Alja Adam, Veronika Ditinjana, Barbara Korun, Anja Golob, Ana Pepelnik, Katja Perat, Lucija Stupica, Ana Svetel, Kaja Teržan, Nataša Velikonja i Maja Vidmar). Okupivši poznatije i prevođenije - kao što su Vidmar i Velikonja, sa na ovim prostorima tek prepoznatim Golob i Korun, ali i uz dostojno predstavljanje najmlađih poput Teržan ili Svetel, antologija želi dati reprezentativan pregled onoga što pjesnikinje u Sloveniji pišu danas', 1, 0, NOW(), NOW()),
  ('Hagada, sarajevska priča', 'Duško Anđić', 20.00, '/images/knjige/1005.webp', 'Hagada - Sarajevska priča knjiga pisana na principu drame sa crno-bijelim fotografijama.', 1, 0, NOW(), NOW()),
  ('Istina iza vrata', 'Zlatko Dizdarević / Tomislav Jakić', 30.00, '/images/knjige/1006.webp', 'Knjiga koju držite u rukama, kad se siđe do suštine, knjiga je dvojice novinara o novinarstvu. A njih dvojica – Zlatko Dizdarević i Tomislav Jakić – pripadali su osamdesetih godina prošlog stoljeća u sami vrh jugoslavenskog i ne samo jugoslavenskog novinarstva: tih godina, naročito u drugoj polovici osamdesetih, profesionalno novinarstvo u Jugoslaviji – usprkos jednopartijskom sistemu, još uvijek snažnoj političkoj kontroli javnog života i ograničenoj slobodi govora – doživljavalo je ozbiljan uzlet. Politička, medijska, obavještajna i vojna nepromišljenost velikih zapadnih sila, predvođenih Sjedinjenim Državama, na Bliskom istoku – u zemljama poput Sirije, Iraka, Libije, Egipta, Jemena... – jedna je od nekoliko točaka u kojima su idejno dodiruju tekstovi Tomislava Jakića i Zlatka Dizdarevića izabrani za ovaj svezak. Kratkovidnost i štetnost zapadne politike prema Bliskom istoku najuvjerljivije je pokazana na recentnom primjeru Sirije. Amerika je, pojednostavljeno, bila ojačala radikalno islamističke monstrume, koji djeluju pod etiketama ISIL-a i Al-Nusre, za potrebe neuspješnog i promašenog rušenja sirijskog totalitarnog režima i predsjednika Asada. Kad su se proizvedeni kanibalistički plaćenici definitivno oteli kontroli, Zapad se odjednom približio dojučerašnjem neprijatelju Asadu: bio je to jedan od preduvjeta globalne kampanje protiv dojučerašnjih saveznika koji su se prometnuli u teroriste i glavosjeke koje valja zasuti bombama. Nikoga nije briga što se Sirija u međuvremenu, tokom rečenog zapadnog lutanja, skoro ugušila u krvi građanskog rata...', 1, 0, NOW(), NOW()),
  ('Jesmo li antisemiti?', 'Hajrudin Somun', 20.00, '/images/knjige/1007.webp', '„Historijske veze balkanskih naroda i zemalja nastalih na prostorima bivše Jugoslavije s Jevrejima i Arapima su stare i mnogostruke, ali ću iz njih pokušati izvući ono što ima posredan ili neposredan značaj za njihove savremene odnose s Izraelom i Palestinom i palestinsko-izraelskim političkim kompleksom. Kao i u mnogočemu drugom, što se danas dešava na Balkanu, korijeni sežu do turskog doba.“', 1, 0, NOW(), NOW()),
  ('Od Kartage do jezera Kunming', 'Borjana i Slobodan Stajić', 20.00, '/images/knjige/1008.webp', 'Rijetkost je da se kao autori knjige zajedno pojavljuju sestra i brat, kao u knjizi „Od Kartage do jezera Kunming“ Borjane i Slobodana Stajića. Nažalost, ovo je i spomen-knjiga, pošto Borjana od 27. marta 2019.g. tihuje u svom vječnom počivalištu na Barama, ali njeni divni putopisi iz sjeverne Afrike, sa Sredozemlja, centralne Evrope i zapisi o drevnom Sarajevu ostaju zauvijek. U svojoj recenziji ugledna novinarka Nada Salom iznosi da je ova knjiga posvećena svim sestrama i svoj braći kojih više nema, navodeći i njen literarni izričaj.', 1, 0, NOW(), NOW()),
  ('Sarajevo  Monografija – Bosanski + eng', 'Više autora', 99.00, '/images/knjige/1009.webp', 'Malo je gradova u svijetu koji su tako zanjmljivi i fotogenični kao Sarajevo, o čemu ova izuzetno lijepo iliustrovana monografija jasno svjedoči. Preko dvije stotine i pedeset umjetničkih fotografija u boji, podržanih zanimljivim tekstom, dočaravaju čitaocu ogromno kulturno nasleđe, život o običaje ljudi različitog porijekla i vjera, koji od pamtivijeka naseljavaju ovaj rijetko živ i uzbudljiv grad. </br> </br> There are few cities in the world that are as captivating and photogenic as Sarajevo, as this exceptionally beautifully illustrated monograph clearly testifies. Over two hundred and fifty color artistic photographs, supported by interesting text, conjure up to the reader a huge cultural heritage, the life and customs of people of different origins and religions, who have inhabited this rarely alive and exciting city since time immemorial.', 1, 0, NOW(), NOW()),
  ('Olimpijsko Sarajevo za nezaborav - monografija', 'Više autora', 89.00, '/images/knjige/1010.webp', '(Po ideji dr. Aziza Hadžihasanovića i Ahmeda Karabegovića): Izdavač Rabic, za izdavača Goran Mikulić, urednik Slobodan Stajić, dizajn i tehnička oprema Dragan S. Stefanović, lektor i korektor Nada Salom, štampa ... Autori storija: Nikola Bilić, Drago Bozja, dr. Aziz Hadžihasanović, Husein Hujić, Ahmed Karabegović, Kemal Kurspahić, dr. sc. Mile Lasić, Dragan Moldovan, Edin Numankadić, Nada Salom, Hajrudin Somun, Vedad Spahović, Slobodan Stajić, Branko Tomić i dr. Ljubiša Zečević. Monografija je nesumnjiv, i nesporan izdavački poduhvat koji je na vrhunski način - i konceptualno, i dokumentovano i likovno-grafički prezentiralo čitaocu vrijeme burnog događanja, dometa i trijumfa civilizacijske sveobuhvatnosti i kreativnosti, priprema i ostvarenja XIV ZOI Sarajevo. Zato ova monografija zaslužuje punu pažnju i puno mjesto u riznici onih istorijskih događaja koji se ne mogu, niti smiju ispustiti iz vida...', 1, 0, NOW(), NOW()),
  ('Tražeći Allaha nađoh Isusa', 'Nabeel Quereshi', 20.00, '/images/knjige/1011.webp', 'U današnjem vremenu agresivne religioznosti, ustvari politizirane religioznosti i religizirane politike, kad je od istinske vjere jedva što ostalo (religiju i vjeru oštro razlikujemo!), manifestacije religijskog jedva da su drukčije vidljive osim kao svaka vrsta nasilja prema drugosti, s tim što je u fizičkom nasilju, čak teroru, najdalje otišlo ono što se predstavlja kao islam. Otuda jedna knjiga koja dolazi iz svijeta islama u kojemu je, ili u čijim je društvima, „otpad od vjere“ sankcioniran prijetnjom smrti, a koja svjedoči promjenu vjerskih i religijskih uvjerenja, pa još u našoj sredini gdje je tako što gotovo nepodnošljivo, s razlogom izaziva pozornost. Naravno takav slučaj i takva knjiga na našem prostoru neće izazvati nemir koji bi u radikalnijim društvima, ali će se u nas sve učiniti da bude prešućena ili da bude u tišinu i gotovo ilegalno kupovana, čitana, ako ne već kupovana i uništavana. A riječ je doista, kako to i kaže podnaslov knjige, o jednom pobožnom islamskom vjerniku koji je susreo kršćanstvo i u tom susretu vidio kako mu njegovi ideolozi govore o tom kršćanstvu, vidio kako to nije ono što ga njegova religija uči o drugom i drukčijem i otkrio sve ono što kršćanstvo nosi u sebi kao pozitivni potenacijal.', 1, 0, NOW(), NOW()),
  ('Katapult', 'Midhat Ajanović', 20.00, '/images/knjige/1012.webp', 'Inženjer, genijalni haker i 3-D animator, koristi Internet kako bi manipulirao ljudima koji žive u imigrantskim predgrađima i lijevičarskim aktivistima koji demonstriraju protiv velike međunarodne konferencija će se, uz prisustvo američkog predsjednika, održati u sjevernoevropskom gradu Nordburgu. On stvara haos u gradu kako bi preusmjerio policijsku pozornost sa vlastitih aktivnosti. Inženjer u potaji stvara ono što on vidi kao svoje životno djelo – najveći teroristički napad stoljeća.Za antiutopijski roman Katapult, filmolog i pisac Midhat Ajanović inspirirao se velikim neredima koji su se dogodili od 14. do 16 juna 2001 u Göteborgu. Roman je objavljen u Hrvatskoj 2003, a prevod na švedski jezik izašao je 2010 u Göteborgu. Ovo je prvi put da se roman pojavljuje u autorovoj domovini.', 1, 0, NOW(), NOW()),
  ('Uspomene / Radost i tuga made in Yuga', 'Toni Skrbinac', 20.00, '/images/knjige/1013.webp', 'Priču o sudbini čuvene sarajevske porodice Merhemić napisao je Toni Skrbinac. To je zbirka njegovih kratkih priča. Skrbinčevo umijeće pripovijedanja i u knjizi Uspomene je dokazano. Umijeće je to za koje teoretičari književnosti znaju reći da je najvažnije u kratkoj priči to da ima svoj fokus, „te da taj fokus onda razbije u fragmente čitateljevu dušu koja se slama pod pritiskom zgusnute narativne težine“. Ni u jednoj priči ništa nije uljepšano i ušminkano. One se sve zajedno mogu čitati i kao slikovita. zanimljiva, topla, i nadasve iskrena biografija. Biografija jednog bistričkog dječaka, novinara, izbjeglice, raseljene osobe... Skrbinac nas poznatim mjestima, stvarima, i prije svega majstorski „oslikanim“ likovima (uvijek su to stvarne ličnosti!) podsjeća na svakodnevne, životne stvari. Na empatiju, koje je, nažalost, sve manje. Uistinu se radi o sjajnom, iskusnom kratkopričašu, novinaru kojemu je institucija kratke priče u krvi, olovci, kompjuteru...', 1, 0, NOW(), NOW()),
  ('Kad sam bio mlađan momak ja', 'Toni Skrbinac', 20.00, '/images/knjige/1014.webp', 'Kad sam bio mlađan momak ja je knjiga sa pričama kao istinskim svjedočanstvima koja stvaraju mozaik jednog vremena kojem sam i kojem još uvijek svjedočim. Bez velikih pretenzija, sa željom da vas zainteresuje i zadrži vašu pažnju. I to je to.', 1, 0, NOW(), NOW()),
  ('Duhovi XV arondismana', 'Jasna Šamić', 25.00, '/images/knjige/1015.webp', 'Novi roman Jasne Šamić, Duhovi Petnaestog arondismana, bavi se bijelim Rusima, naseljenim u Parizu, i njihovim sadašnjim potomcima, kao i Rusima koji od nedavno žive u Normandiji. Ono što ih ujedinjuje, pored nostalgije za zemljom, jeste i „cirkus“ koji organiziraju, ili su organizirali odmah po dolasku u Pariz, zabave koje svedoče o obliku očajničke egzaltacije i duševne boli za zemljom porijekla. Ovaj roman je općenito priča o izbjeglištvu, o nostalgiji za bivšom domovinom, o nesnalaženju slavenskog čovjeka u inozemstvu, naročito na Zapadu. Najzad, može li se zaključiti da je to i priča o sukobu dva svijeta?', 1, 0, NOW(), NOW()),
  ('Panika u kupaonici', 'Mirjana Grbac Pismestrović', 20.00, '/images/knjige/1016.webp', 'Zbirka je 36 humorističnih priča koje će vas zabaviti. Priče su potpuno samostalne i zaokružene cjeline, ne oduzimaju previše vremena i mogu se čitati jedna po jedna. Realistične tematike poput odnosa u obitelji, prijateljstva, pogleda žene,majke... upotpunjene su humorom i neobičnim zgodama. Njezine priče teku bez zastoja, neumitno kao što prolazi vrijeme.', 1, 0, NOW(), NOW()),
  ('Sarajevska Hagada', 'Rabic', 99.00, '/images/knjige/1017.webp', 'Priča o sarajevskoj Hagadi zaista je jedinstvena. Knjiga, nastala negdje kod Barselone oko 1350. godine, stigla je u BiH u šesnaestom vijeku, zajedno s Jevrejima Sefardima, prognanim iz Španije. Nakon što je stotinama godina u Sarajevu korištena za praznike, Hagada je 1894. godine prodana Zemaljskom muzeju u Sarajevu. Tokom Drugog svjetskog rata, direktor muzeja Jozo Petrović i kustos Derviš Korkut spasili su je od Nijemaca, rekavši visokom njemačkom oficiru da je već iznesena iz muzeja. Jedna od legendi kaže da je tokom Drugog svjetskog rata Hagada bila zakopana ispod praga jedne džamije na Bjelašnici. U posljednjem ratu u BiH, Hagadu su spasili profesor doktor Enver Imamović i četiri policajca, koji su pod kišom granata i snajperskih metaka, knjigu izvukli iz muzeja i odnijeli je u sef Narodne banke. Profesor Imamović kaže da je veoma sretan što je danas Hagada prevedena na engleski i bosanski jezik. “Biće vrlo pristupačna svima koji se interesiraju za to kulturno i vjersko blago naših sugrađana Jevreja koji s nama ovdje žive još od početka šesnaestog stoljeća“, kaže on. Kulturna i istorijska vrijednost originalne Hagade, koja se čuva u Zemaljskom muzeju BiH, je neprocjenjiva. Materijalna vrijednost je zadnji put, 1992. godine, tokom velike izložbe Jevreja Sefarda u Madridu, procijenjena na sedam miliona dolara. „Čuli smo tokom rata priče da je vlada u Sarajevu prodala Hagadu i kupila oružje i municiju“, kaže profesor Imamović. On dodaje da su te priče prestale kada je Hagada pokazana svjetskoj javnosti u opkoljenom Sarajevu 1995. godine, sa ogromnim mjerama osiguranja. Za BiH i Jevreje koji žive u njoj, Hagada je znatno više od bilo kakve materijalne vrijednosti , ona je dokaz njihovog prisustva u ovoj zemlji u proteklih pet vijekova.', 1, 0, NOW(), NOW()),
  ('Stećci - Monografija', 'Dubravko Lovrenović', 35.00, '/images/knjige/1030.webp', 'Nakon što su četiri stoljeća – od kraja bosanskog srednjovjekovlja do prvih decenija XIX. stoljeća – bili prepušteni zaboravu, ljudskoj destrukciji i “umiranju” u prirodi, bosanski i humski nadgrobni spomenici stećci probudili su najprije zanimanje putopisaca i znatiželjnika koji su pohodili Bosnu i Hercegovinu. Od uspostave Muzejskog društva Bosne i Hercegovine 1884, preko utemeljenja Zemaljskog muzeja Bosne i Hercegovine 1888, što znači od prvih sustavnih nastojanja oko znanstvene valorizacije stećaka, ovi su bosanski i humski srednjovjekovni nadgrobni spomenici postali predmetom multidisciplinarnih istraživanja domaćih i inozemnih stručnjaka, počevši od historičara i arheologa do historičara umjetnosti, etnologa, jezikoslovaca, folklorista i znanstvenika drugih usmjerenja. Ni pjesnička ni slikarska imaginacija nije ostala imuna na njihovu tajnovitu monumentalnost, koja je proizvodila i još uvijek proizvodi najfantastičnije predodžbe o njihovu podrijetlu te umjetničkoj i vjerskoj funkciji. Oslanjajući se na dosadašnje rezultate, zapravo prezentirajući najvažnija dostignuća izučavanja stećaka sabrana tijekom više od jednoga stoljeća, ova monografija nastoji otići korak dalje uklapajući fenomen stećaka u kontekst europske sepulkralne umjetnosti, bolje rečeno u kontekst rednjovjekovnoga govora o smrti.', 1, 0, NOW(), NOW()),
  ('THE SARAJEVO HAGADAH - monograph', 'Više autora', 99.00, '/images/knjige/1025.webp', 'The Popular Monograph Edition of the Sarajevo Haggadah is aimed at the wide circle of readers with an interest in this unique medieval manuscript. It printed to the highest graphic standard in offset gold technique to bring out the full beauty of the illustrations and calligraphy. The format will be 240 x 300 mm – larger than the original manuscript in order to magnify the details. The Popular Edition of the Sarajevo Haggadah has 288 pages, of which 39 are reproductions of folios with full-page illuminations in colour, six folios of large pictures with text, 71 folios of illuminated text in colour, 19 folios of coloured calligraphy, and 110 folios of text. It include a scholarly introduction and explanatory text by Dr Jakob Finci, President of the Jewish Community of Bosnia and Herzegovina, with its seat in Sarajevo.', 1, 0, NOW(), NOW()),
  ('Sarajevska Hagada', 'reprint izdanje sa ukrasnom kutijom', 200.00, '/images/knjige/1026.webp', 'Tiraž ove publikacije je u više hiljada primjeraka. Štampano petobojno, bez ručne dorade i luksuzne opreme i kao tako odštampanoj, cijena joj je na tržištu kao i svakoj drugoj knjizi radjenoj na taj način. </br> </br> We have just completed a reprint edition of the original Sarajevo Haggadah with a decorative box. There are no embellishments or any other additions. This more modest looking edition sells at only 100 euros (without shipping costs). 1.500 copies were immediately bought by an American book dealer and of the remaining 500 copies we have already sold 180 copies. The current price is 100 euros. As is customary, we offer discount for purchases of large numbers of copies.', 1, 0, NOW(), NOW()),
  ('Sarajevska Hagada', 'faksimilno izdanje', 3.80, '/images/knjige/1027.webp', 'Ručna dorada,zlatotisak, kožni uvez, kutija / luksuzna oprema, 95% sliči originalu - namjenjena kolekcionarima, ljubiteljima lijepih rariretnih knjiga. Radjena je na prijedlog predsjednika svjetskog Jevrejskog kongresa g. Singera. Ovaj faksimil posjeduje i certifikat Jevresjske zajednice Sarajevo. Istim se garantuje da se više neće raditi drugo izdanje (uništena sva priprema da do toga ne bi došlo). Ograničeni tiraz od 613 primjeraka ima i svoju simboliku. Talmud ima 613 sura i zapovijedi a po drugom vjerovanju sveta voćka Nar kada se otvori ima 613 zrna a svako zrno je jedna lijepa želja. Početna cijena Facsimila je bila 1.150 €. Kako je običaj kod Facsimilnih izdanja smanjenjem broja preostalih primjeraka ( ostalo jos 70 komada ) cijena se povećava. Trenutna cijena je 1.750 €. Na certifikatu se po želji kupca može odštampati ime budućeg vlasnika - sito štampa. </br> </br> FACSIMILE EDITION. Following the recommendation of Mr. Singer, president of the World Jewish Congress at the time, we published 613 copies in this edition. The book was additionally embelished by a Sarajevo artist and all other things were done to make it a proper facsimile edition. After the publication of the book all the printing infrastructure was destroyed to prevent a possible pirate publication. Every buyer of this edition of the The Sarajevo Hagadah is provided with a certificate issued by the Jewish Community of Bosnia and Herzegovina that the number of copies in this edition does not exceed 613. The original price of the book was 1.150 euros. As the number of available copies decreased, the price was raised first to 1.400 and then to 1.750 euros. The current price is 1.750 and we expect it to go up to 2.500 euros before the end of the year.', 1, 0, NOW(), NOW()),
  ('TOMBSTONES THE BOSNIAN AND HUM MEDIAEVAL GRAVEYARDS', 'Dubravko Lovrenović', 85.00, '/images/knjige/1028.webp', 'Having been for four centuries – from the end of the Bosnian Middle Ages to the early decades of the 19th century – left to oblivion, human destruction and "dying" in nature, the Bosnian and Hum tomb markers stećci aroused interest first of travel writers and inquisitive persons visiting Bosnia and Herzegovina. Since the foundation of the Museum Society of Bosnia and Herzegovina in 1884 and the establishment of the National Museum of Bosnia and Herzegovina thereafter in 1888, i.e. from the first systematic attempts to scientifically evaluate the stećci, these Bosnian and Hum mediaeval tombstones have been a subject of multidisciplinary investigations of both local and foreign experts, from historians and archaeologists to art historians, ethnologists, linguists, folklorists and scholars in other fields. Neither poets'' nor painters'' imagination has remained indifferent to their secretive monumentality, producing ever since the most fantastic perceptions of their origin and their artistic and religious purposes. Relying heavily on the results achieved to date, this monograph is an attempt to make a step further placing the stećak phenomenon into the context of European sepulchral art, or better to say into the context of mediaeval talk about death.', 1, 0, NOW(), NOW()),
  ('THE SARAJEVO ASSASSINATION / One Hundred Years Later', 'Grupa autora', 89.00, '/images/knjige/1029.webp', 'The Sarajevo Assassination attached an evil connotation to the name of Sarajevo in history books, and a hundred years later the event is being commemorated, in documentary and artistic ways, with all its actual or potential historical, mythical, social and political meaning. We have been completely open - as we suggest with the title – to every relevant way of thinking about this historic event and its real or otential repercussions, and we have invited contributions from some of the best qualified people in the region and in countries with which Bosnia and Herzegovina shares the destiny of having once belonged to Austria-Hungary... The book you have in your hands is the product of this aspiration. It is ambitious but not, we hope, pretentious. The contributions of those who accepted the challenge are published in this book with a view not simply to asking questions or providing answers, but to marking a year in which the capital of Bosnia and Herzegovina entered the world stage, and to making a small contribution to a consideration of the century that has passed, its changes and how these changes have affected us. As a result, this book offers a variety of historiographical insights, and suggests a background for a portrait of a historic event. At the same time it fictionalises some aspects of the event as a gift to the imagination of readers who understand that books are there to be read and not exclusively to resolve the crucial questions of the world. Autors of texts: Ivo Banac, Ivo Goldstein, Latinka Perović, Filip David, Svetislav Basara, Milan Zemko, Miljenko Jergović.', 1, 0, NOW(), NOW()),
  ('Stećci - Monografija', 'Dubravko Lovrenović', 150.00, '/images/knjige/1019.webp', 'Pisano čitko i popularno, ali uz sav neophodan naučni aparat i sa izuzetno korisnim indeksima ličnih imena i geografskih pojmova. Ovaj tekst prodiraće neposredno do publike različitog stepena obavještenosti o temi, pamtiće se po zanimljivim i korisnim podacima i njihovom povezivanju u značenju cjeline koje otvaraju nove vizure. Opisi su precizni, podaci kritički odabrani. Inovativan u pristupu, besprijekoran i cjelovit po sadržaju, profesionalno sveden na neophodno i neopterećujuće, ali sa elementima koji potiču na dalja traganja, tekst profesora Dubravka Lovrenovića u svemu ispunjava zahtjeve modernog naučnog štiva. </br> </br> It is very well written, legibly and popularly, but with all the necessary scientific apparatus and with extremely useful indexes of personal names and geographical terms. This text will penetrate directly to the audience of different levels of information about the topic, it will be remembered for interesting and useful information and their connection in the meaning of the whole that opens up new vistas. The descriptions are precise, the data critically selected. Innovative in its approach, impeccable and complete in content, professionally reduced to the necessary and unburdening, but with elements that encourage further research, the text by Professor Dubravko Lovrenović in everything meets the requirements of modern scientific reading.', 1, 0, NOW(), NOW()),
  ('0:4 za nas', 'Zlatko Dizdarević', 20.00, '/images/knjige/2001.webp', 'Tog proljeća, prvog pod opsadom, mnogi su počeli da pišu dnevnike, da čitaju... Što se autora ove knjige tiče, uprkos svemu, dileme pisati ili ne, nikada nije bilo. Njemu/nama je, u tom ratu oduzeto sve osim činjenice da „smo ostali Sarajlije u svakom smislu te nevjerovatne riječi, i divno se osjećamo u tom siromaštvu.“ Novinaru, piscu, sjajnom dopisniku sa Bliskog Istoka, kasnije i diplomati, bile su pored matičnih otvorene stranice brojnih listova u Evropi i Americi. Kratka su to originalna kazivanja o Sarajlijama prvih godina rata kada su trebali ostati ljudi (pa i uljuđeni), kazivanja koja postaju i ostaju dobri glas Sarajeva. Nema krvi, nema užasa (samo pismo jedne mlade stanovnice Ilidže… – priču prepričava poznati sarajevski liječnik… dovoljna je!), nema čak ni straha...', 1, 0, NOW(), NOW()),
  ('Šesta flota u Miljacki', 'Zlatko Dizdarević', 20.00, '/images/knjige/2002.webp', 'Tekstovi pisani u Sarajevu za vrijeme minulog rata i tada objavljivani u "Slobodnoj Dalmaciji" iz Splita nisu sada ponovo pred nama samo radi pukog prisjećanja na to ko smo i kakvi bili onda. Oni nam na specifičan pokazuju koliko se ono što se nama dešavalo tada, kao realnost na najgori način ponavlja i mnogim drugim po svijetu danas. Do cinizma je puno toga isto danas kao i onda u onome što se zove jad i bijeda svjetske politike i njenih kreatora i izvođača. Ma koliko smo tada, i pored svega, vjerovali da neće biti tako...', 1, 0, NOW(), NOW()),
  ('5 + smrtnih grehova', 'Margit Tomik Levi', 20.00, '/images/knjige/2003.webp', 'U Sarajevu na izborima su najmanje glasali građani, stanovnici tih izbornih jedinica, ljudi... Nisu glasali ni konstitutivni narodi. Glasali su muslimani za muslimane, pravoslavci za pravoslavce, katolici za katolike, narkomani za narkomane, LGBTiovci za LGBTiovce, lopovi za lopove... Nije se glasalo za NiP nego protiv SDA-a…', 1, 0, NOW(), NOW()),
  ('Anđeli i demoni', 'Toni Skrbinac', 20.00, '/images/knjige/2004.webp', 'Autobiografska knjiga od 37 priča gdje se spominje isto toliko likova poznatih sarajevskoj čaršiji. Priče su autentični događaji koje je autor doživio sa Abdulahom Sidranom, Dariom Džamonjom, Ivicom Osimom, Sašom Lošić i drugima.', 1, 0, NOW(), NOW()),
  ('Čovječuljak iz septičke jame i druge priče o znakovima', 'Nadan Filipović', 20.00, '/images/knjige/2005.webp', 'Ovako počinje knjiga priča o životnim znakovima, koje nam autor Nadan Filipović nudi i predstavlja nam i opisuje poznata imena, naše sugrađane sa druge ružnije strane. “Ne očekujem da će većina čitatelja povjerovati u ove priče koje nisam, pri kraju svog puta, htio ostaviti nezapisanim, ali, siguran sam, da će neko povjerovati u barem neke detalje, a neki će se, možda i prepoznati. Uostalom, neka bude zapisano, jer u stvarnosti, zna se, ostaje samo ono što je “ubijelo” zapisano.”', 1, 0, NOW(), NOW()),
  ('Diplomatija bez protokola - Drugi dio', 'Slobodan Stajić', 30.00, '/images/knjige/2006.webp', 'Knjiga Diplomatmija bez protokola (Il dio) višestruko je zanimljivo štivo. Mozaičnog je karaktera - složena od autorovih intervjua, pričica iz historije diplomatije, novinarske riječi o nedavnim i ovovremenim važnim međunarodnim zbivanjima, ključnim međunarodnim organizacijama i ličnostima u njima, diplomatskom aspektu raspada SFRJ, o tragediji BiH u evropskom i svjetskom interesnom kolopletu, jugoslovenskim i bh. spoljnopolitičkim akterima, Stajićevim žurnalističkim svjedočenjima, komentatorskim refleksijama, reporterskim sličicama, naknadnim zapažanjima i bilješkama, te uspjesima, zanimljivostima, bizarnostima i crnim stranicama u svijetu diplomata... Stajićeva knjiga je rijetkost jer se tematski bavi diplomatijom, kao specifičnim političkim zanatom, koji je kod nas prisutan gotovo isključivo u tekućim vijestima. To je prva vrijednost knjige, koju slijede informativnost, dokumentarnost, edukacijski aspekt...', 1, 0, NOW(), NOW()),
  ('Majka kraljica Katarina Kosača Kotromanić', 'Nataša Bartula', 25.00, '/images/knjige/2007.webp', 'Autorica Nataša Bartula Hebert posvećuje svoj romaneskni tekst jednoj izuzetnoj ženi iz srednjovjekovne bosanske povijesti, Katarini Kosači koja se udaje za bosanskog kralja Stjepana Tomaša Kotromanića. Rukopis polazi od trenutaka samoće Katarine Kosače Kotromanić u Rimu, u izbjeglištvu, daleko od domovine, kada se odmotava povijest, priča i strašni udes srednjovjekovne bosanske kraljevine pred rušilačkim naletom Osmanske vojske. Autorica često koristi povijesne činjenice i događaje te ih planski uokviruje u pripovijedni sadržaj koji dobija romanesknu formu. Imaginacijska struktura postaje vidljiva forma empatije, dubokog razumijevanja i ljubavi prema Katarini.', 1, 0, NOW(), NOW()),
  ('Mario Mikulić: sjećanja, slike, bilješke, crteži, govori i pisanja', 'Goran Mikulić', 40.00, '/images/knjige/2008.webp', 'O Mariu – Milivoje Begenišić: “Postoji drevna istočnjačka legenda o slikaru geniju. Ona glasi otprilike ovako : slikar je bio obdaren toliko da je na platnu i papiru stvarao život lepši i čudesniji od onoga stvarnog. Jednog dana slikar, ne zna se razlog a on nije ni bitan, kada završi svoje platno uputi se tim naslikanim predelima, preseli se na sliku, i isčezne. Ljudi i danas gledaju te divne slike tražeći i slikara na njima. Možda će ga i slike vratiti iz večnosti i u prolaznost i svakodnevnicu. Za slikara Marija Mikulića mogla bi legenda da glasi da lirskom nežnošću i stvaralačkim umećem preseljava ljude i predele na svoja platna. Sa njima živi i druži se u snu i na javi… Profesionalno sam pratio stvaralaštvo Marija Mikulića od izložbe do izložbe - i uvek iznova doživljavao njegovu snažnu povezanost sa ljudima i podnebljem naših prostora, sa raspećima i izletima našeg veka. On je njihov pesnik bojama. Govornik platnom. Mislilac složenim slikarskim kompozicijama koji taj život dešifruju i obelodanjuju. Niko od njega na tako impresivan način nije dao lice ulice. To je pozornica življenja kao mostovi i vode kod Ive Andrića”.', 1, 0, NOW(), NOW()),
  ('Moć', 'dr. Belma Hadžiomerović', 35.00, '/images/knjige/2009.webp', '“Moć”, knjiga koju je napisala dr. Belma Hadžiomerović, bavi se ključnim pitanjem liderstva u modernom poslovnom i osobnom kontekstu. Autorica se oslanja na svoje tridesetogodišnje iskustvo u međunarodnom menadžmentu i koristi znanje iz neuroznanosti i emocionalne inteligencije kako bi ponudila holistički pristup samoupravljanju i vođenju drugih. Glavna premise knjige je da liderstvo nije samo skup vještina, već način života koji zahtijeva kontinuirani osobni rast, svjesnost i odgovornost. Knjiga nudi jedinstvenu kombinaciju teorije i prakse, temeljenu na znanstvenim principima neuroplastičnosti i emocionalne inteligencije, koji su integrirani s osobnim iskustvima autorice.', 1, 0, NOW(), NOW()),
  ('PTSP spomenar', 'Dragan Bursać', 20.00, '/images/knjige/2010.webp', 'Bursać nam je, eto, nekad bio Nikoletina, a danas nam je Dragan. Blagi, dobri Gaga za nas prijatelje, a plećati Draganetina za dušmane, fašiste i njihove pomagače, ponio je svoje teško prezime - mobiliziran baš kao prvi i pravi Nikoletina, pa baš kao i on odmetnut u partizane - da nastavi tamo gdje je njegov slavni rođak stao: s prstom na tastaturi kao na obaraču, „mitraljezac golubinjeg srca“ opkoljen višestruko nadmoćnijim neprijateljem, na čuki na kojoj je svakom čestitom Bursaću vazda bilo mjesto. I jezik je njegov ćopićevski, krajiški, onaj na kojemu ljubav grmi, a revolucija pjeva, sav narodski i narodan, da ga bolje razumiju u narodu koji se Bursaćevih odrekao. Rijetki su i teški poštenje i čast s kojim se tako grmi i pjeva, pa nema u Bosni i Hercegovini usamljenijega i težega prezimena da ga čovjek sa sobom ponese, nego što je to slavno prezime Dragana Bursaća.', 1, 0, NOW(), NOW()),
  ('Žuta kabanica', 'Dragan Bursać', 20.00, '/images/knjige/2011.webp', 'O stradanju i zločinima pišu mnogi, ali je Dragan jedinstven u poziciji onih koji ne pristaju na relativizaciju motiva i cilja u ratovima devedesetih, pa secira svaki segment politike koji je doveo do genocida, masovnih zločina i etničkih progona, prepoznajući ih u mitomansko ratnim narativima savremene politike. “Žute kabanice” je beskrajno tužna i uznemirujuća, ali istovremeno i knjiga - riznica nade. Uvijek i svuda takve su knjige dragocjene. U društvima okovanim etnofilijom, društvima koja funkcionišu kao zajednice hipokrizije i laži, Bursaćeva knjiga je još važnija. Njena vrijednost i snaga ne mogu biti precijenjene. Jer ona nas uči: ne zajednica krvi, nego zajednica vrijednosti. Ne etnička, nego etička zajednica.', 1, 0, NOW(), NOW()),
  ('Pabrici iz budućnosti s prostora današnjih država Hrvatske i Srbije 2053.', 'Predrag Daraboš', 20.00, '/images/knjige/2012.webp', 'U svojoj suštini, i naizgled paradoksalno, Pabirci iz budućnosti su dokument amoralnog bezumlja aktualne sadašnjosti i alternativnih prošlosti naroda slavenske kulture koji nastanjuju geografsko područje Balkanskog poluotoka. Ovo djelo će, čitatelju donekle upućenom u umjetničku i filozofsku književnost, prizvati u sjećanje Pohvalu Ludosti Erazma Roterdamskog – kako zbog njegovog pretežito satiričnog tona, tako i zbog izvanredne erudicije autora. Uistinu, Pabirci iz budućnosti su jedinstvena futuristička kronika visoko intelektualne proze, višeslojne narativne strukture i reskog humora; no, njihov najvrjedniji doprinos emocionalnom životu pojedinca i političkoj uobrazilji društva je ipak ponuđena mogućnost temeljne katarze, koja, za razliku od Aristotelove, djeluje putem medija komedije i groteske.', 1, 0, NOW(), NOW()),
  ('Pariški susret', 'Gradimir Gojer', 15.00, '/images/knjige/2013.webp', 'Najnovija pesnička knjiga akademika Gradimira Gojera predstavlja veliki pesnički poduhvat njegovog internacionalnog horizonta i na književnom i na istorijskom planu. On nije samo alhemičar univerzalne misli nego i veliki ujedinitelj Balkana, Evrope i Sveta. Naslov “Pariški susret” može biti vezan za mnoge duhovne odiseje o Gradu svetlosti, ali asocijacija koju je pre više od jednog stoleća napisao Antun Gustav Matoš: “Na pariskim ulicama u pet minuta ima više duha nego u Pruskoj akademiji nauka u 5 vekova”, prava je estetička anticipacija ove Gojerove knjige. U svim pesmama imate utisak da se čitava plejada likova, događaja, gradova, slike i prilike susreću u imaginarnom Parizu koji je iznad života, duboko u realnosti koja je Gojerovim perom pretvorena u realnost koja nam prožima srce.', 1, 0, NOW(), NOW()),
  ('Sarajevska lektira asova', 'Milorad Bjelogrlić', 20.00, '/images/knjige/2014.webp', 'U najstereotipnijoj slici Sarajeva unutar ostatka Jugoslavije, a stereotipi postaju stereotipi jer su na jednom nivou tačni, Sarajevo je grad muzike i sporta. I zaista, imajući u vidu objektivnu veličinu i važnost Sarajeva u Jugoslaviji, i unutar muzike i unutar sporta, značaj ljudi iz Sarajeva bio je višestruko veći nego se to moglo očekivati. Autor je ispričao životne sudbine svojih/naših sportskih ljubimaca, ali isto tako je opisao neke značajne sportske događaje koji su se desili u našem rodnom i najdražem gradu. Skoro svi oni o kojima je pisao su igrali i bili u zenitu karijere kada je i autorovo „ludilo” za sportom bilo na vrhuncu.', 1, 0, NOW(), NOW()),
  ('Srce, duša i krv: knj. 1 i knj. 2', 'Tonćo Ladan', 35.00, '/images/knjige/2015.webp', 'Ljubavna priča prepuna radosne ljubavi, beskrajne tuge i napete radnje u društvu u kojem oživljeni nacionalizam ostavlja pojedincu malo prostora da donese osobnu ulogu svog osobnog identiteta. Sudbine ljudi su često vezane s njihovim mjestom rođenja ostavljajući neizbrisiv trag na njima i u njima. Roman otkriva kako svako doba ima svoje obilježje iskazano na ljudskim osjećanjima u međuljudskim odnosima i ne samo da istražuje te odnose nego preispituje uvjete koji su doveli do njih.', 1, 0, NOW(), NOW()),
  ('Šamar je informacija iz prve ruke', 'grupa autora', 25.00, '/images/knjige/2016.webp', 'Knjigom dominiraju bosanskohercegovački autori (satiričari, aforističari i karikaturisti) i već spominjani Splićani-feralovci, ali zar bi se uopće mogla zamisliti satira na našim prostorima bez stvarnih klasika kakvi su Duško Radović, Vladimir Bulatović Vib, Aleksandar Baljak, Ratko Božović ili u karikaturi Predrag Koraksić Corax ili Petar Pismestrović? Ova knjiga je rađena za zabavu čitanja i zadržala se samo na satiri pisanoj na prostorima našeg četveroimenog jezika tijekom zadnjih desetljeća u obliku, ovdje dominantno, priča i aforizama, te crteža i karikatura kojim se slikovno komentiralo, izvrgavalo poruzi ono negativno u društvu ili u ljudskoj prirodi, napose u sferi politike, koja na našim prostorima živi svoju rudimentarnu bit. Čitatelj će vidjeti kako knjiga nije niti ima namjeru biti antologijski izbor, niti reprezentativni uzorak naše satire, ona je htjela biti i jest čitanka, knjiga za čitanje, jednako ozbiljna onima koje satira ozbiljno zanima, kao i jednako neozbiljna onima kojima je satira dobar povod za dobar smijeh, dobro raspoloženje, i ništa manje kao kvalitetna intelektualna mozgalica na putovanju, na plaži, uz uzglavlje za zdravo uspavljivanje... Ili, ako baš hoćete malo ambicioznije, jer nijedna od ovih heretičkih priča ili aforizama nije pisana bez ozbiljnih ambicija, kao izazov našoj podaničkoj, poslušničkoj, vjerničko-ideološkoj prirodi...', 1, 0, NOW(), NOW()),
  ('U đul bašti', 'Emsura Hamzić', 20.00, '/images/knjige/2017.webp', 'Oduvijek je čovjek imao potrebu da svaku svoju sreću ali i tugu i nesreću, a možda ove potonje i prevashodno, iskaže kroz riječi, kroz ritam, kroz muziku, tj. kroz spoj riječi i nekog ritma, melodije, kajde... Jedna od najsnažnijih kombinacija jeste svakako lirska narodna pjesma, koja je vremenom odjenuta u muzičko ruho. Ovo je nova knjiga Emsure Hamzić pod nazivom ”U đul bašti – sevdalinka kao nematerijalno kulturno nasleđe”. Najkraću i najjezgrovitiju neformalnu odrednicu sevdalinke dao je jedan dječak: “Sevdalinka je ono kad moj babo pjeva i – plače!!!”', 1, 0, NOW(), NOW());
